VAR Cuenta =
    SELECTEDVALUE('origenesdecontabilidad-TEST'[ClassCG])

VAR EsSubnivel =
    ISINSCOPE('origenesdecontabilidad-TEST'[SubClassCG])

VAR EsFilaClass =
    ISINSCOPE('origenesdecontabilidad-TEST'[ClassCG])

VAR MontoBase =
    SUM('origenesdecontabilidad-TEST'[amrusd])

-- Revenue total
VAR Revenue =
    CALCULATE(
        SUM('origenesdecontabilidad-TEST'[amrusd]),
        REMOVEFILTERS('origenesdecontabilidad-TEST'[ClassCG]),
        'origenesdecontabilidad-TEST'[ClassCG] = "Revenue"
    )

-- DWP base
VAR DWP_Base =
    CALCULATE(
        SUM('origenesdecontabilidad-TEST'[amrusd]),
        REMOVEFILTERS('origenesdecontabilidad-TEST'[ClassCG]),
        'origenesdecontabilidad-TEST'[ClassCG] = "DWP"
    )

VAR DWP_Final =
    DWP_Base + Revenue

RETURN
SWITCH(
    TRUE(),

    -- 🔹 Subniveles
    EsSubnivel,
        MontoBase,

    -- 🔹 Nivel ClassCG
    EsFilaClass,
        SWITCH(
            TRUE(),

            Cuenta = "DWP",
                MontoBase + Revenue,

            Cuenta = "Operational Result",
                MontoBase + DWP_Final,

            MontoBase
        ),

    -- 🔴 TOTAL
    SUMX(
        VALUES('origenesdecontabilidad-TEST'[ClassCG]),
        SWITCH(
            TRUE(),

            'origenesdecontabilidad-TEST'[ClassCG] = "DWP",
                CALCULATE(SUM('origenesdecontabilidad-TEST'[amrusd])) + Revenue,

            'origenesdecontabilidad-TEST'[ClassCG] = "Operational Result",
                CALCULATE(SUM('origenesdecontabilidad-TEST'[amrusd])) + DWP_Final,

            CALCULATE(SUM('origenesdecontabilidad-TEST'[amrusd]))
        )
    )
