</style>"


-- ============================================================
-- ORDEN DE GRUPOS
-- ============================================================
VAR _orden = DATATABLE(
    "grp",   STRING,
    "ord",   INTEGER,
    "color", STRING,
    {
        {"Ventas Totales",                           1, "#EBEBEB"},
        {"Costos de Operación",                      2, "#EBEBEB"},
        {"EBITDA",                                   3, "#B8B8B8"},  
        {"Gastos de Administración",                 4, "#EBEBEB"},
        {"Utilidad Operativa",                       5, "#B8B8B8"},  
        {"EBIT",                                     6, "#B8B8B8"},
        {"Utilidad / (Pérdida) Antes de Impuestos",  7, "#EBEBEB"}
    }
)

-- ============================================================
-- MESES
-- ============================================================

VAR _meses = 
    ADDCOLUMNS(
        FILTER(
            VALUES( calendariocontable[month_en] ),
            NOT ISBLANK( calendariocontable[month_en] ) &&
            CALCULATE( SUM('origenesdecontabilidad-TEST'[amrusd]) ) <> 0
        ),
        "ord",
            SWITCH(
                TRUE(),
                calendariocontable[month_en] = "Jan",1,
                calendariocontable[month_en] = "Feb",2,
                calendariocontable[month_en] = "Mar",3,
                calendariocontable[month_en] = "Apr",4,
                calendariocontable[month_en] = "May",5,
                calendariocontable[month_en] = "Jun",6,
                calendariocontable[month_en] = "Jul",7,
                calendariocontable[month_en] = "Aug",8,
                calendariocontable[month_en] = "Sep",9,
                calendariocontable[month_en] = "Oct",10,
                calendariocontable[month_en] = "Nov",11,
                calendariocontable[month_en] = "Dec",12
            )
    )

VAR _numMeses = COUNTROWS(_meses)

VAR _anio = SELECTEDVALUE( calendariocontable[año], "2026" )

VAR _thMeses = CONCATENATEX( _meses, "<th>" & calendariocontable[month_en] & "</th>", "", [ord] )

VAR _thead =
    "<thead>
        <tr>
            <th rowspan='2' style='vertical-align:middle;text-align:center;border-bottom:none;'>Class / Sub-Class</th>
            <th colspan='" & _numMeses & "' class='yh'>" & _anio & "</th>
            <th rowspan='2' class='yh ct' style='vertical-align:middle;border-bottom:none;'>YTD</th>
        </tr>
        <tr>" & _thMeses & "</tr>
    </thead>"

-- ============================================================
-- GRUPOS CON ORDEN
-- ============================================================
VAR _grupos =
    SELECTCOLUMNS(
        _orden,
        "ClassCG", [grp],
        "ord_g",   [ord],
        "colorG",  [color]   
    )

-- ============================================================
-- CONSTRUCCION DE FILAS
-- ============================================================
VAR _filas =
    CONCATENATEX(
        _grupos,
        VAR _g   = [ClassCG]
        VAR _gid = SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(_g," ","_"),"/","_"),"&","_")
        VAR _colorFila1 = [colorG]  
        VAR _celdasGrupo =
            CONCATENATEX(
                _meses,
                VAR _m = calendariocontable[month_en]

                VAR _baseG =
                SUMX(
                    FILTER(
                        VALUES('origenesdecontabilidad-TEST'[SubClassCG]),
                        NOT ISBLANK('origenesdecontabilidad-TEST'[SubClassCG])
                    ),
                    CALCULATE(
                        SUM('origenesdecontabilidad-TEST'[amrusd]),
                        'origenesdecontabilidad-TEST'[ClassCG] = _g,
                        calendariocontable[month_en] = _m
                    )
                )

                VAR _ventas =
                    CALCULATE(
                        SUM('origenesdecontabilidad-TEST'[amrusd]),
                        'origenesdecontabilidad-TEST'[ClassCG] = "Ventas Totales",
                        calendariocontable[month_en] = _m
                    )

                VAR _costos =
                    CALCULATE(
                        SUM('origenesdecontabilidad-TEST'[amrusd]),
                        'origenesdecontabilidad-TEST'[ClassCG] = "Costos de Operación",
                        calendariocontable[month_en] = _m
                    )

                VAR _gastosAdmin =
                    CALCULATE(
                        SUM('origenesdecontabilidad-TEST'[amrusd]),
                        'origenesdecontabilidad-TEST'[ClassCG] = "Gastos de Administración",
                        calendariocontable[month_en] = _m
                    )

                VAR _ebit =
                    CALCULATE(
                        SUM('origenesdecontabilidad-TEST'[amrusd]),
                        'origenesdecontabilidad-TEST'[ClassCG] = "EBIT",
                        calendariocontable[month_en] = _m
                    )

                VAR _ebitda = _ventas - _costos


                VAR _v =
                    SWITCH(
                        TRUE(),

                        _g = "EBITDA",
                            _ventas - _costos,

                        _g = "Utilidad Operativa",
                            _ebitda - _gastosAdmin,

                        _g = "EBIT",
                            (_ebitda - _gastosAdmin) + _ebit,

                        _g = "Utilidad / (Pérdida) Antes de Impuestos",
                            ((_ebitda - _gastosAdmin) + _ebit) + _baseG,

                        _baseG
                    )

                VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                VAR _fmt = IF( ISBLANK(_v), "", IF( _v < 0, "-" & FORMAT( ROUND( ABS(_v) / 1000, 0 ), "#,##0" ),FORMAT( ROUND( _v / 1000, 0 ), "#,##0" ) ) )
                RETURN "<td class='" & _cls & "' style='background:" & _colorFila1 & "'>" & _fmt & "</td>",
                "", [ord]
            )

        VAR _baseGTotal =
            SUMX(
                FILTER(
                    VALUES('origenesdecontabilidad-TEST'[SubClassCG]),
                    NOT ISBLANK('origenesdecontabilidad-TEST'[SubClassCG])
                ),
                CALCULATE(
                    SUM('origenesdecontabilidad-TEST'[amrusd]),
                    'origenesdecontabilidad-TEST'[ClassCG] = _g
                )
            )

        VAR _ventasTotal =
            CALCULATE(
                SUM('origenesdecontabilidad-TEST'[amrusd]),
                'origenesdecontabilidad-TEST'[ClassCG] = "Ventas Totales"
            )

        VAR _costosTotal =
            CALCULATE(
                SUM('origenesdecontabilidad-TEST'[amrusd]),
                'origenesdecontabilidad-TEST'[ClassCG] = "Costos de Operación"
            )

        VAR _gastosAdminTotal =
            CALCULATE(
                SUM('origenesdecontabilidad-TEST'[amrusd]),
                'origenesdecontabilidad-TEST'[ClassCG] = "Gastos de Administración"
            )

        VAR _ebitTotal =
                    CALCULATE(
                        SUM('origenesdecontabilidad-TEST'[amrusd]),
                        'origenesdecontabilidad-TEST'[ClassCG] = "EBIT"
                    )

        VAR _ebitdaTotal = _ventasTotal - _costosTotal

        VAR _totalG =
            SWITCH(
                TRUE(),

                _g = "EBITDA",
                    _ventasTotal - _costosTotal,

                _g = "Utilidad Operativa",
                    _ebitdaTotal - _gastosAdminTotal,

                _g = "EBIT",
                    (_ebitdaTotal - _gastosAdminTotal) - _ebitTotal,

                _g = "Utilidad / (Pérdida) Antes de Impuestos",
                            ((_ebitdaTotal - _gastosAdminTotal) + _ebitTotal) + _baseGTotal,

                _baseGTotal
            )

        VAR _totalGCls = IF( NOT ISBLANK(_totalG) && _totalG < 0, " neg", "" )
        VAR _totalGFmt =
        IF(
            ISBLANK(_totalG),
            "",
            IF(
                _totalG < 0,
                "-" & FORMAT( ROUND( ABS(_totalG) / 1000, 0 ), "#,##0" ),
                FORMAT( ROUND( _totalG / 1000, 0 ), "#,##0" )
            )
        )

        VAR _colorFila = [colorG]

        VAR _filaGrupo =
            "<tr class='gh' style='--row-bg:" & _colorFila & ";'
            onclick=""var rows=this.parentNode.querySelectorAll('[data-g=&quot;" & _gid & "&quot;]');
                var ico=this.querySelector('.ico');
                var open=ico.textContent==='-'; 
                Array.prototype.forEach.call(rows,function(r){
                    r.style.display=open?'none':'';
                });
                ico.textContent=open?'+':'-';
                this.classList.toggle('active');
                "">
                <td style='background:" & _colorFila & "'><div class='gl'><span class='tog'><span class='ico'>-</span></span>" & _g & "</div></td>"
            & _celdasGrupo &
            "<td class='ct" & _totalGCls & "' style='background:" & _colorFila & "'>" & _totalGFmt & "</td></tr>"

VAR _esVirtual =
    _g IN {
        "EBITDA",
        "Utilidad Operativa"}

VAR _hijos =
    FILTER(
        SELECTCOLUMNS(
            ADDCOLUMNS(
                CALCULATETABLE(
                    FILTER(
                        VALUES('origenesdecontabilidad-TEST'[SubClassCG]),
                        NOT ISBLANK('origenesdecontabilidad-TEST'[SubClassCG])
                    ),
                    'origenesdecontabilidad-TEST'[ClassCG] = _g
                ),
                "ord_h",
                    CALCULATE(
                        MAX('origenesdecontabilidad-TEST'[SubClassCG_Order])
                    )
            ),
            "SubClassCG", 'origenesdecontabilidad-TEST'[SubClassCG],
            "ord_h", [ord_h]
        ),
        NOT _esVirtual
    )

VAR _countHijos =
    COUNTROWS(_hijos)

        VAR _filasHijos =
            CONCATENATEX(
                _hijos,
                VAR _h = [SubClassCG]
                VAR _hid = _gid & "_" & SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(_h," ","_"),"/","_"),"&","_")
                VAR _index =
                    RANKX(
                        _hijos,
                        COALESCE([ord_h],9999),
                        ,
                        ASC,
                        DENSE
                    )

                -- ============================================================
                -- NIVEL 3: campo de detalle
                -- Para cambiar la columna de detalle, solo se modifica
                -- la columna referenciada en VALUES() y en los CALCULATE()
                -- El nombre interno "montoHijo" no cambia nunca
                -- ============================================================
                VAR _detalles =
                    ADDCOLUMNS(
                        FILTER(
                            VALUES('origenesdecontabilidad-TEST'[nombreproveedor]),  -- << CAMBIAR AQUI
                            NOT ISBLANK('origenesdecontabilidad-TEST'[nombreproveedor])  -- << CAMBIAR AQUI
                        ),
                        "montoHijo",
                            VAR _tmp =
                                CALCULATE(
                                    SUM('origenesdecontabilidad-TEST'[amrusd]),
                                    'origenesdecontabilidad-TEST'[ClassCG] = _g,
                                    'origenesdecontabilidad-TEST'[SubClassCG] = _h
                                )
                            RETURN ABS(_tmp)
                    )

                VAR _detallesFiltrados =
                    FILTER(
                        _detalles,
                        [montoHijo] <> 0
                    )

                VAR _filasDetalle =
                    CONCATENATEX(
                        _detallesFiltrados,
                        VAR _d = 'origenesdecontabilidad-TEST'[nombreproveedor]  -- << CAMBIAR AQUI

                        VAR _celdasDetalle =
                            CONCATENATEX(
                                _meses,
                                VAR _m = calendariocontable[month_en]

                                VAR _v =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-TEST'[amrusd]),
                                        'origenesdecontabilidad-TEST'[ClassCG] = _g,
                                        'origenesdecontabilidad-TEST'[SubClassCG] = _h,
                                        'origenesdecontabilidad-TEST'[nombreproveedor] = _d,  -- << CAMBIAR AQUI
                                        calendariocontable[month_en] = _m
                                    )

                                VAR _cls = IF(ISBLANK(_v),"",IF(_v<0," neg",""))
                                VAR _fmt =
                                    IF(ISBLANK(_v),"",
                                        IF(_v<0,
                                            "-" & FORMAT(ROUND(ABS(_v)/1000,0),"#,##0"),
                                            FORMAT(ROUND(_v/1000,0),"#,##0")
                                        )
                                    )

                                RETURN "<td class='"&_cls&"'>"&_fmt&"</td>",
                                "", [ord]
                            )

                        VAR _totalD =
                            CALCULATE(
                                SUM('origenesdecontabilidad-TEST'[amrusd]),
                                'origenesdecontabilidad-TEST'[ClassCG] = _g,
                                'origenesdecontabilidad-TEST'[SubClassCG] = _h,
                                'origenesdecontabilidad-TEST'[nombreproveedor] = _d  -- << CAMBIAR AQUI
                            )

                        VAR _totalDCls = IF( NOT ISBLANK(_totalD) && _totalD < 0, " neg", "" )
                        VAR _totalDFmt =
                            IF(ISBLANK(_totalD),"",
                                IF(_totalD<0,
                                    "-" & FORMAT(ROUND(ABS(_totalD)/1000,0),"#,##0"),
                                    FORMAT(ROUND(_totalD/1000,0),"#,##0")
                                )
                            )

                        RETURN
                        "<tr class='sh2' data-h='"&_hid&"' style='display:none'>
                            <td style='padding-left:40px'>"&_d&"</td>"
                        & _celdasDetalle &
                        "<td class='ct"&_totalDCls&"'>"&_totalDFmt&"</td></tr>",
                        "", [montoHijo], DESC
                    )

                VAR _extraClass =
                    IF(_index = 1, " first", "") &
                    IF(_index = _countHijos, " last", "")

                VAR _celdasHijo =
                    CONCATENATEX(
                        _meses,
                        VAR _m = calendariocontable[month_en]

                        VAR _v =
                            CALCULATE(
                                SUM( 'origenesdecontabilidad-TEST'[amrusd] ),
                                'origenesdecontabilidad-TEST'[ClassCG] = _g,
                                'origenesdecontabilidad-TEST'[SubClassCG]  = _h,
                                calendariocontable[month_en] = _m
                            )
                        VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
