                " & _p & "
            </div>

        </th>",
        "", [ord_p], DESC
    )

-- ============================================================
-- ENCABEZADO FILA 2: año repetido por pozo
-- ============================================================
VAR _thAnios =
    CONCATENATEX(
        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[dataareaid]
        VAR _mesesPozo =
            FILTER( _pozoMes, 'origenesdecontabilidad-PL'[dataareaid] = _p )
        VAR _numM = COUNTROWS( _mesesPozo )
        VAR _rankPozo =
        RANKX( _pozos, [ord_p], , DESC, DENSE )
        RETURN
            "<th
                id='hy" & _rankPozo & "'
