        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[dataareaid]
        VAR _mesesPozo =
            FILTER( _pozoMes, 'origenesdecontabilidad-PL'[dataareaid] = _p )
        VAR _rankPozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
        VAR _thM =
