-- ============================================================
-- ORDEN DE CLASES
-- ============================================================
VAR _ordenClass = DATATABLE(
    "grp", STRING, "ord", INTEGER,
    {{"Revenue",1},{"DWP",2},{"Operational Result",3},{"Sin Clasificar",4}}
)
-- ============================================================
-- CLASES GLOBALES
-- ============================================================
VAR _grupos =
    ADDCOLUMNS(
        FILTER(
            VALUES( 'origenesdecontabilidad-PL'[ClassCG] ),
            NOT ISBLANK( 'origenesdecontabilidad-PL'[ClassCG] )
            && 'origenesdecontabilidad-PL'[ClassCG] <> "Sin Clasificar"
        ),
        "ord_g",
            MAXX( FILTER( _ordenClass, [grp] = 'origenesdecontabilidad-PL'[ClassCG] ), [ord] )
    )

-- ============================================================
-- CONSTRUCCIÓN DE FILAS
-- ============================================================
VAR _filas =
    CONCATENATEX(
        _grupos,
        VAR _g   = 'origenesdecontabilidad-PL'[ClassCG]
        VAR _gid = SUBSTITUTE( SUBSTITUTE( SUBSTITUTE( _g, " ", "_" ), "/", "_" ), "&", "_" )
        VAR _grandTotal =
            SWITCH(
                TRUE(),

                _g = "Revenue",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] = "Revenue"
                    ),

                _g = "DWP",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP"}
                    ),

                _g = "Operational Result",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] IN {
                            "Revenue",
                            "DWP",
                            "Operational Result"
                        }
                    )
            )

        VAR _grandFmt =
            IF(
                ISBLANK(_grandTotal),
                "",
                IF(
                    _grandTotal < 0,
                    "-" & FORMAT( ROUND( ABS(_grandTotal)/1000, 0 ), "#,##0" ),
                    FORMAT( ROUND( _grandTotal/1000, 0 ), "#,##0" )
                )
            )

        VAR _grandCls =
            IF( NOT ISBLANK(_grandTotal) && _grandTotal < 0, " neg", "" )

        -- Celdas del grupo: para cada pozo, sus meses
        VAR _celdasGrupo =
            CONCATENATEX(
                _pozos,
                VAR _p = 'origenesdecontabilidad-PL'[dataareaid]
                VAR _mesesPozo = FILTER( _pozoMes, 'origenesdecontabilidad-PL'[dataareaid] = _p )
                VAR _rankPozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
                VAR _tds =
                    CONCATENATEX(
                        _mesesPozo,
                        VAR _m = calendariocontable[month_en]
                        VAR _revenue =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[dataareaid] = _p,
                                'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                                calendariocontable[month_en] = _m
                            )

                        VAR _dwp =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[dataareaid] = _p,
                                'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                                calendariocontable[month_en] = _m
                            )

                        VAR _op =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[dataareaid] = _p,
                                'origenesdecontabilidad-PL'[ClassCG] = "Operational Result",
                                calendariocontable[month_en] = _m
                            )

                        VAR _v =
                            SWITCH(
                                TRUE(),
                                _g = "Revenue",
                                    _revenue,
                                _g = "DWP",
                                    _revenue + _dwp,
                                _g = "Operational Result",
                                    _revenue + _dwp + _op,
                                BLANK()
                            )
                        VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                    VAR _fmt =
                        IF( ISBLANK(_v), "",
                            IF( _v < 0,
                                "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                                FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                            )
                        )
                        RETURN  "<td style='display:none;' class='data p" & _rankPozo & "" & _cls & "'>" & _fmt & "</td>",
                        "", [ord_m]
                    )

                   VAR _revTotal =
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[dataareaid] = _p,
                            'origenesdecontabilidad-PL'[ClassCG] = "Revenue"
                        )

                    VAR _dwpTotal =
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[dataareaid] = _p,
                            'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                        )

                    VAR _opTotal =
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[dataareaid] = _p,
                            'origenesdecontabilidad-PL'[ClassCG] = "Operational Result"
                        )

                    VAR _totalPozo =
                        SWITCH(
                            TRUE(),
                            _g = "Revenue",_revTotal,
                            _g = "DWP",_revTotal + _dwpTotal,
                            _g = "Operational Result",_revTotal + _dwpTotal + _opTotal,
                            BLANK()
                        )

                VAR _fmtTotal =
                    IF( ISBLANK(_totalPozo), "",
                        IF( _totalPozo < 0,
                            "-" & FORMAT( ROUND( ABS(_totalPozo)/1000, 0 ), "#,##0" ),
                            FORMAT( ROUND( _totalPozo/1000, 0 ), "#,##0" )
                        )
                    )
                VAR _clsTotal =
                    IF(
                        ISBLANK(_totalPozo),
                        "",IF(_totalPozo < 0, " neg", "")
                    )

                RETURN
                    _tds &
                    "<td class='total" & _clsTotal & "'>" &
                        _fmtTotal &
                    "</td>",
                "", [ord_p], DESC
            )

        VAR _filaGrupo =
            "<tr class='gh'
                onclick=""var rows=this.parentNode.querySelectorAll('[data-g=&quot;" & _gid & "&quot;]');
                    var ico=this.querySelector('.ico');
                    var open=ico.textContent==='-';
                    Array.prototype.forEach.call(rows,function(r){ r.style.display=open?'none':''; });
                    ico.textContent=open?'+':'-';
                    this.classList.toggle('active');
                "">
                <td class='sticky-col'><div class='gl'><span class='tog'><span class='ico'>-</span></span>" & _g & "</div></td>"
            & _celdasGrupo &
            "<td class='grandtotal" & _grandCls & "'>" &
                _grandFmt &
            "</td>
            </tr>"

        -- SubClases
        VAR _hijos =
            ADDCOLUMNS(
                FILTER(
                    CALCULATETABLE(
                        VALUES( 'origenesdecontabilidad-PL'[SubClassCG] ),
                        'origenesdecontabilidad-PL'[ClassCG] = _g
                    ),
                    NOT ISBLANK( 'origenesdecontabilidad-PL'[SubClassCG] )
                ),
                "ord_h",
                    CALCULATE( MAX( 'origenesdecontabilidad-PL'[SubClassCG_Order] ) )
            )

        VAR _countHijos = COUNTROWS( _hijos )
        VAR _filasHijos =
            CONCATENATEX(
                _hijos,
                VAR _h      = 'origenesdecontabilidad-PL'[SubClassCG]
                VAR _providersBase =
                    FILTER(

                        ADDCOLUMNS(
                            SUMMARIZE(
                                FILTER(
                                    'origenesdecontabilidad-PL',
                                    'origenesdecontabilidad-PL'[ClassCG] = _g &&
                                    'origenesdecontabilidad-PL'[SubClassCG] = _h
                                ),

                                'origenesdecontabilidad-PL'[nombreproveedor]
                            ),

                            "amt",
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd])
                                ),

                            "abs_amt",
                                ABS(
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd])
                                    )
                                )
                        ),
                        [amt] <> 0
                    )
               VAR _topProvidersTable =
                TOPN(
                    10,
                    _providersBase,
                    [abs_amt], DESC
                )

                VAR _providerTooltip =
                CONCATENATEX(
                    _topProvidersTable,

                    'origenesdecontabilidad-PL'[nombreproveedor]
                        & ":::"
                        & FORMAT( ROUND([amt] / 1000, 0), "#,##0" ),

                    "|",

                    [abs_amt], DESC
                )

                VAR _indexH = RANKX( _hijos, [ord_h], , ASC, DENSE )
                VAR _celdasHijo =
                    CONCATENATEX(
                        _pozos,
                        VAR _p = 'origenesdecontabilidad-PL'[dataareaid]
                        VAR _mesesPozo = FILTER( _pozoMes, 'origenesdecontabilidad-PL'[dataareaid] = _p )
                        VAR _rankPozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
                        VAR _tds =
                            CONCATENATEX(
                                _mesesPozo,
                                VAR _m = calendariocontable[month_en]
                                VAR _v =
                                    CALCULATE(
                                        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                                        'origenesdecontabilidad-PL'[dataareaid]       = _p,
                                        'origenesdecontabilidad-PL'[ClassCG]    = _g,
                                        'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                        calendariocontable[month_en] = _m
                                    )
                                VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                                VAR _fmt =
                                    IF( ISBLANK(_v), "",
                                        IF( _v < 0,
                                            "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                                            FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                                        )
                                    )


                                RETURN "<td style='display:none;' class='data p" & _rankPozo & "" & _cls & "'>" & _fmt & "</td>",
                                "", [ord_m]
                            )

                        VAR _totalPozo =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[dataareaid] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                                    )
                        VAR _fmtTotal =
                            IF( ISBLANK(_totalPozo), "",
                                IF( _totalPozo < 0,
                                    "-" & FORMAT( ROUND( ABS(_totalPozo)/1000, 0 ), "#,##0" ),
                                    FORMAT( ROUND( _totalPozo/1000, 0 ), "#,##0" )
                                )
                            )
                        VAR _clsTotal =
                            IF(
                                ISBLANK(_totalPozo),
                                "",
                                IF(_totalPozo < 0, " neg", "")
                            )
                        RETURN
                            _tds &
                            "<td class='total" & _clsTotal & "'>" &
                                _fmtTotal &
                            "</td>",
                        "", [ord_p], DESC
                    )

                VAR _esPrimerGrupo = [ord_g] = 1

                VAR _extraH =
                    IF( _esPrimerGrupo && _indexH = 1, " first-global", "" ) &
                    IF( _indexH = 1, " first", "" ) &
                    IF( _indexH = _countHijos, " last", "" )

                VAR _grandSub =
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                    )

                VAR _grandSubFmt =
                    IF(
                        ISBLANK(_grandSub),
                        "",
                        IF(
                            _grandSub < 0,
                            "-" & FORMAT( ROUND( ABS(_grandSub)/1000 , 0 ), "#,##0" ),
                            FORMAT( ROUND( _grandSub/1000 , 0 ), "#,##0" )
                        )
                    )

                VAR _grandSubCls =
                    IF(
                        ISBLANK(_grandSub),
                        "",
                        IF(_grandSub < 0, " neg", "")
                    )



                RETURN
                    "<tr class='sh" & _extraH & "' data-g='" & _gid & "' style='display:table-row'>
                        <td class='sticky-col subclass-cell'

                    data-tip='" & _providerTooltip & "'

                    " & IF(
                        _enableProviderTooltip,

                        "onclick='showProviderTooltip(this,event)'
                        onmouseleave='hideProviderTooltip()'",

                        ""
                    ) & ">

                    <div class='gl'>
                            <span style='width:20px;display:inline-block;'></span>" & _h & "
                        </div></td>"

                    & _celdasHijo &

                    "<td class='grandtotal " & _grandSubCls & "'>" &
                        _grandSubFmt &
                    "</td>

                    </tr>","", [ord_h]
            )



        --RETURN _filaGrupo & _filasHijos, --se expande hacia abajo
        RETURN _filasHijos & _filaGrupo, -- se expande hacia arriba
        "", [ord_g]
    )


VAR _script = 
"
<script>

function setPozoState(rank, open) {
    var p = 'p' + rank;
    var hp = document.getElementById('hp' + rank);
    if (!hp) return;

    var full = parseInt(hp.getAttribute('data-full'), 10);
    if (isNaN(full) || full < 1) full = 1;

    // Celdas de datos
    var cols = document.querySelectorAll('td.' + p + ', th.' + p);
    cols.forEach(function(c) {
        c.style.display = open ? '' : 'none';
    });

    // Header de anio
    var hy = document.getElementById('hy' + rank);
    if (hy) {
        hy.colSpan = open ? full : 1;
        hy.style.display = open ? '' : 'none';
    }

    // Header Total de meses
    var totalHeaders = document.querySelectorAll('.thtotalp' + rank);
    totalHeaders.forEach(function(c) {
        c.style.display = open ? '' : 'none';
    });

    hp.setAttribute('colspan', open ? full : 1);
    hp.setAttribute('data-open', open ? '1' : '0');
}

function expandAllPozos() {
    var headers = Array.prototype.slice.call(
        document.querySelectorAll('th.ph')
    );
    var ranks = headers.map(function(h) {
        return h.id.replace('hp', '').trim();
    });
    ranks.forEach(function(rank) {
        setPozoState(rank, true);
    });
}

function collapseAllPozos() {
    var headers = Array.prototype.slice.call(
        document.querySelectorAll('th.ph')
    );
    var ranks = headers.map(function(h) {
        return h.id.replace('hp', '').trim();
    });
    ranks.forEach(function(rank) {
        setPozoState(rank, false);
    });
}


function showProviderTooltip(el, evt){

    var tooltip = document.getElementById('providerTooltip');

    if(!tooltip) return;

    var raw = el.getAttribute('data-tip');

    if(!raw || raw.trim() === '') return;

    var rows = raw.split('|');

    var html = '<div class=""tt-title"">Top 10 Proveedores / Clientes</div>';

rows.forEach(function(r){

    var p = r.split(':::');

    var name = p[0] || '';
    var val  = p[1] || '';
    var cls = val.indexOf('-') >= 0
    ? 'tt-val neg'
    : 'tt-val';

    html +=
        '<div class=""tt-row"">' +
            '<span class=""tt-name"">' + name + '</span>' +
            '<span class=""' + cls + '"">' + val + '</span>' +
        '</div>';
});

    tooltip.innerHTML = html;

    tooltip.style.display = 'block';

    var mouseX = evt.pageX;
    var mouseY = evt.pageY;

    var tooltipWidth  = tooltip.offsetWidth;
    var tooltipHeight = tooltip.offsetHeight;

    var windowWidth  = window.innerWidth;
    var windowHeight = window.innerHeight;

    var left = mouseX + 15;
    var top  = mouseY + 15;

    /* =====================================================
    SI SE SALE POR ABAJO → MOSTRAR HACIA ARRIBA
    ===================================================== */

    if(top + tooltipHeight > windowHeight){

        top = mouseY - tooltipHeight - 25;
    }

    /* =====================================================
    SI SE SALE POR DERECHA → MOSTRAR HACIA IZQUIERDA
    ===================================================== */

    if(left + tooltipWidth > windowWidth){

        left = mouseX - tooltipWidth - 25;
    }

    /* =====================================================
    APPLY
    ===================================================== */

    tooltip.style.left = left + 'px';
    tooltip.style.top  = top  + 'px';
}

function hideProviderTooltip(){

    var tooltip = document.getElementById('providerTooltip');

    if(tooltip){
        tooltip.style.display = 'none';
    }
}

</script>
"

