VAR _style = "<style>
/* ============================================================
   RESET GENERAL
   Elimina márgenes y padding de todos los elementos
============================================================ */
*{box-sizing:border-box;margin:0;padding:0;}

/* ============================================================
   CONTENEDOR PRINCIPAL
   Fuente, tamaño base y scroll horizontal si la tabla es ancha
============================================================ */
.tw{
    font-family: Segoe UI SemiBold, Arial, sans-serif;
    font-size:14px;
    overflow-x:auto;
    width:100%;
} 

/* ============================================================
   TABLA
   Ancho completo, sin separación entre bordes
   min-width: ancho mínimo antes de activar scroll
============================================================ */
table{
    width:auto;
    border-collapse:separate;
    border-spacing: 1.5px;
    background:rgba(0,0,0,0.08);
    min-width:auto;
    table-layout: fixed;   /* Anchos independientes */
}

/* ============================================================
   ENCABEZADOS (TH)
   border-bottom: línea inferior que separa encabezado de datos
   border-top: línea superior del encabezado (opcional)
============================================================ */
th{
    background:#1A1A1A;
    color:#FFF;
    padding:5px 8px;
    text-align:center;
    font-weight:600;
    font-size:15px;
    white-space:nowrap;
    border-right:0px solid #CCCCCC;   /* borde entre columnas */
    border-bottom:0px solid #CCCCCC;  /* << borde inferior del encabezado - abajo del año */
    border-top:0px solid #CCCCCC;     /* << borde superior (opcional) */
}

/* ============================================================
   PRIMERA COLUMNA DEL ENCABEZADO
   'Class / Sub-Class' — alineada al centro, ancho fijo
============================================================ */
th:first-child{
    text-align:center;
    width:30px;
}
td:first-child{
    width: 60px;   /*  Ancho primera columna */
}

/* ============================================================
   ENCABEZADO DEL AÑO (fila superior del thead)
   Mismo fondo que th, centrado
============================================================ */
th.yh{
    text-align:center;
    background:#1A1A1A;
}

/* ============================================================
   ANCHO DE COLUMNAS DE MESES Y DATOS
   Aplica a todos los th y td excepto la primera columna
============================================================ */
th:not(:first-child),
td:not(:first-child){
    width: 90px;   /* Ancho de cada mes */
    min-width: 90px;
}

/* ============================================================
   COLUMNA YTD/TOTAL  — ANCHO
   th.ct y td.ct controlan el ancho de la columna Total
============================================================ */
th.ct,
td.ct{
   width: 90px;   /*Ancho del total */
   min-width: 90px;
}

/* ============================================================
   CELDAS DE DATOS (TD)
   Centrado, borde inferior y derecho, sin salto de línea
============================================================ */
td{
    padding:4px 4px;
    text-align:center;
    border-bottom:0px solid #E5E5E5;
    border-right:0px solid #E5E5E5;
    white-space:nowrap;
}

/* ============================================================
   PRIMERA CELDA DE DATOS
   Texto alineado a la izquierda con sangría
============================================================ */
td:first-child{
    text-align:left;
    padding-left:10px;
    width:100px;
}

/* ============================================================
   FILAS DE GRUPO PRINCIPAL (Class: Revenue, DWP, Op. Result)
   Fondo gris, texto negro, cursor pointer para el clic
============================================================ */
tr.gh td{
    background:#CCCCCC;
    color:#000000;
    font-weight:500;
    font-size:14.5px;
    cursor:pointer;
    border-top:1px solid #CCCCCC;
}

/* ============================================================
   BORDE SUPERIOR DE FILAS DE GRUPO
   Separación visual entre grupos
============================================================ */
tr.gh td{
    border-top:0px solid #ffffff;
}

/* ============================================================
   FILAS HIJAS NIVEL 1 (SubClass)
   Fondo ligeramente azulado
============================================================ */
tr.sh td{
    background:#FFF;
}

/* ============================================================
   FILAS HIJAS NIVEL 2 (Detalle)
   Fondo ligeramente más oscuro que nivel 1
============================================================ */
tr.sh2 td {
    background: #F6F5F5;   
}

/* ============================================================
   PRIMERA CELDA DE FILAS HIJAS NIVEL 1
   Sangría mayor + color de texto
