    border-bottom:0px solid #fff;
}

/* ============================================================
   VALORES NEGATIVOS — COLOR
   Aplica a celdas con clase .neg en cualquier nivel
============================================================ */
.neg{color:#0073FF;}
tr.gh .neg{color:#0073FF;}
tr.sh .ct.neg{color:#0073FF !important;}
tr.sh2 .ct.neg{color:#0073FF !important;}
tr.gh .ct.neg{color:#0073FF !important;}

/* ============================================================
   COLUMNA TOTAL — FILA DE GRUPO (gh)
   Fondo gris, texto negro, negrita
============================================================ */
.ct{
    background:#CCCCCC 
    color:#000 
    font-weight:600;
    font-size:14px;
}

/* ============================================================
   COLUMNA TOTAL — ENCABEZADO (th)
   Fondo oscuro, texto blanco
============================================================ */
th.ct{
    background:#1A1A1A !important;
    color:#fff !important;
    font-weight:600;
    font-size:15px;
}

/* ============================================================
   COLUMNA TOTAL — FILAS HIJAS NIVEL 1 (SubClass)
   Fondo ligeramente azulado, igual que la fila
============================================================ */
tr.sh .ct{
    background:#f7f8fc 
    color:#000 
}

/* ============================================================
   COLUMNA TOTAL — FILAS HIJAS NIVEL 2 (Pozo/Detalle)
   Fondo ligeramente más oscuro que nivel 1
============================================================ */
tr.sh2 .ct{
    background:#f4f6fb 
    color:#000 
}

/* ============================================================
   BOTÓN EXPANDIR/COLAPSAR [ + / - ]
   Cuadro pequeño a la izquierda del nombre de grupo
============================================================ */
.tog{
    display:inline-flex;
    align-items:center;
    justify-content:center;
    width:15px;
    height:15px;
    border:0.5px solid #EBEBEB;
    border-radius:1.5px;
    margin-right:10px; /* Sangria del expansor con el texto */
