/* ============================================================
   CONTENEDOR FLEX PARA BOTÓN + TEXTO
   Alinea el ícono y el nombre en la misma línea
============================================================ */
.gl{
    display:flex;
    align-items:center;
}

/* ============================================================
   NEGRITA AL SELECCIONAR UNA FILA
   Se activa con la clase .active al hacer clic
   Para desactivar: comentar este bloque completo
============================================================ */
tr.active td:first-child{
    font-weight:700;
}

</style>"
