VAR _orden = DATATABLE(
    "grp", STRING, "ord", INTEGER,
    {{"Revenue",1},{"DWP",2},{"Operational Result",3},{"Sin Clasificar",4}}
)

-- ============================================================
-- CAMBIO 1: PERIODOS = AÑO + MES (antes era solo mes)
-- Colocamos esto para que cada combinación año-mes sea una
-- columna independiente, así no se mezclan los años.
-- ============================================================
VAR _periodos =
    ADDCOLUMNS(
        FILTER(
            SUMMARIZE( calendariocontable, calendariocontable[año], calendariocontable[month_en] ),
            NOT ISBLANK( calendariocontable[month_en] ) &&
            CALCULATE( SUM('origenesdecontabilidad-PL'[amrusd]) ) <> 0
        ),
        "ordMes",
            SWITCH( 
                TRUE(),
                calendariocontable[month_en] = "Jan",1,
                calendariocontable[month_en] = "Feb",2,
                calendariocontable[month_en] = "Mar",3,
                calendariocontable[month_en] = "Apr",4,
                calendariocontable[month_en] = "May",5,
                calendariocontable[month_en] = "Jun",6,
                calendariocontable[month_en] = "Jul",7,
                calendariocontable[month_en] = "Aug",8,
                calendariocontable[month_en] = "Sep",9,
                calendariocontable[month_en] = "Oct",10,
                calendariocontable[month_en] = "Nov",11,
                calendariocontable[month_en] = "Dec",12
            ),
        "ordGlobal",
            calendariocontable[año] * 100 +
            SWITCH(
                TRUE(),
                calendariocontable[month_en] = "Jan",1,
                calendariocontable[month_en] = "Feb",2,
                calendariocontable[month_en] = "Mar",3,
                calendariocontable[month_en] = "Apr",4,
                calendariocontable[month_en] = "May",5,
                calendariocontable[month_en] = "Jun",6,
                calendariocontable[month_en] = "Jul",7,
                calendariocontable[month_en] = "Aug",8,
                calendariocontable[month_en] = "Sep",9,
                calendariocontable[month_en] = "Oct",10,
                calendariocontable[month_en] = "Nov",11,
                calendariocontable[month_en] = "Dec",12
            )
    )

VAR _columnas =
UNION(

    SELECTCOLUMNS(
        _periodos,
        "Anio", calendariocontable[año],
        "Mes", calendariocontable[month_en],
        "Orden", [ordGlobal],
        "EsYTD", FALSE()
    ),

    SELECTCOLUMNS(
        VALUES(calendariocontable[año]),
        "Anio", calendariocontable[año],
        "Mes", "YTD",
        "Orden", calendariocontable[año] * 100 + 13,
        "EsYTD", TRUE()
    )
)

VAR _numPeriodos = COUNTROWS(_periodos)

-- ============================================================
-- CAMBIO 2: LISTA DE AÑOS SELECCIONADOS (para armar el header)
-- ============================================================
VAR _anios =
    ADDCOLUMNS(
        VALUES(calendariocontable[año]),
        "colspanAnio",
            COUNTROWS(
                FILTER(
                    _periodos,
                    calendariocontable[año] = EARLIER(calendariocontable[año])
                )
            ) + 1
    )
VAR _numAnios =
    COUNTROWS(_anios)

VAR _mostrarPTD =
    _numAnios > 1
-- ============================================================
-- CAMBIO 3: THEAD DINÁMICO POR AÑO
-- Cambiamos acá: antes había un solo bloque con _anio fijo,
-- ahora recorremos _anios y por cada uno generamos su colspan
-- con sus meses correspondientes.
-- ============================================================
VAR _thAnios =
    CONCATENATEX(
        _anios,
        "<th colspan='" & [colspanAnio] & "' class='yh'>" & calendariocontable[año] & "</th>",
        "", calendariocontable[año]
    )

VAR _thMeses =
    CONCATENATEX(
        _columnas,
        "<th" &
            IF([EsYTD], " class='ct'", "") &
        ">" &
            [Mes] &
        "</th>",
        "",
        [Orden]
    )

VAR _thead =
    "<thead>
        <tr>
            <th rowspan='2' style='vertical-align:middle;text-align:center;border-bottom:none;'>Class / Sub-Class</th>"
            & _thAnios &
            IF(
                _mostrarPTD,
                "<th rowspan='2' class='yh ct'style='vertical-align:middle;border-bottom:none;'>PTD</th>",
                ""
            ) &
    "</tr>
    <tr>" & _thMeses & "</tr>
    </thead>"

-- ============================================================
-- GRUPOS CON ORDEN
-- ============================================================
VAR _grupos =
    FILTER(
        ADDCOLUMNS(
            FILTER( VALUES( 'origenesdecontabilidad-PL'[ClassCG] ), 
            NOT ISBLANK( 'origenesdecontabilidad-PL'[ClassCG] ) 
             && 'origenesdecontabilidad-PL'[ClassCG] <> "Sin Clasificar"
            ),"ord_g", MAXX( FILTER( _orden, [grp] = 'origenesdecontabilidad-PL'[ClassCG] ), [ord] )
        ),
        NOT ISBLANK( [ord_g] )
    )

-- ============================================================
-- CONSTRUCCION DE FILAS
-- ============================================================
VAR _filas =
    CONCATENATEX(
        _grupos,
        VAR _g   = 'origenesdecontabilidad-PL'[ClassCG]
        VAR _gid = SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(_g," ","_"),"/","_"),"&","_")

        -- CAMBIO 4: iteramos por _periodos en vez de _meses,
        -- y agregamos calendariocontable[año] = _y en cada CALCULATE
            VAR _celdasGrupo =
                CONCATENATEX(
                    _columnas,

                    VAR _y = [Anio]
                    VAR _esYTD = [EsYTD]
                    VAR _m = [Mes]

               VAR _baseG =
                SUMX(
                    FILTER(
                        VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                        NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                    ),
                    IF(
                        _esYTD,
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG]=_g,
                            calendariocontable[año]=_y
                        ),

                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG]=_g,
                            calendariocontable[año]=_y,
                            calendariocontable[month_en]=_m
                        )
                    )
                )

                VAR _rev_m =
                    SUMX(
                        FILTER(
                            VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                            NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                        ),
                        IF(
                        _esYTD,
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                            calendariocontable[año]=_y
                        ),
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                            calendariocontable[año]=_y,
                            calendariocontable[month_en]=_m
                        )
                    )
                )

                VAR _dwp_m =
                    SUMX(
                        FILTER(
                            VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                            NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                        ),
                        IF(
                        _esYTD,
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                            calendariocontable[año]=_y
                        ),
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                            calendariocontable[año]=_y,
                            calendariocontable[month_en]=_m
                        )
                    )
                )

                VAR _v =
                    SWITCH(
                        TRUE(),
                        _g = "DWP",               _baseG + _rev_m,
                        _g = "Operational Result", _baseG + _dwp_m + _rev_m,
                        _baseG
                    )

                VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                VAR _fmt = IF( ISBLANK(_v), "", IF( _v < 0, "-" & FORMAT( ROUND( ABS(_v) / 1000, 0 ), "#,##0" ),FORMAT( ROUND( _v / 1000, 0 ), "#,##0" ) ) )
                RETURN
                    "<td class='" & _cls & "'>" & _fmt & "</td>",
                "",
                [Orden]
                )

        -- El YTD (total) se mantiene igual: no filtra por mes ni año,
        -- así que respeta automáticamente todos los años seleccionados
        VAR _baseGTotal =
            SUMX(
                FILTER(
                    VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                    NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                ),
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    'origenesdecontabilidad-PL'[ClassCG] = _g
                )
            )

        VAR _revTotal =
            SUMX(
                    FILTER(
                        VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                        NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                    ),
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] = "Revenue"
                    )
                )

        VAR _dwpTotal =
            SUMX(
                    FILTER(
                        VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                        NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                    ),
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                    )
                )

        VAR _totalG =
            SWITCH(
                TRUE(),
                _g = "DWP",               _baseGTotal + _revTotal,
                _g = "Operational Result", _baseGTotal + _dwpTotal + _revTotal,
                _baseGTotal
            )

        VAR _totalGCls = IF( NOT ISBLANK(_totalG) && _totalG < 0, " neg", "" )
        VAR _totalGFmt =
        IF(
            ISBLANK(_totalG),
            "",
            IF(
                _totalG < 0,
                "-" & FORMAT( ROUND( ABS(_totalG) / 1000, 0 ), "#,##0" ),
                FORMAT( ROUND( _totalG / 1000, 0 ), "#,##0" )
            )
        )

        VAR _filaGrupo =
            "<tr class='gh' 
            onclick=""var rows=this.parentNode.querySelectorAll('[data-g=&quot;" & _gid & "&quot;]');
                var ico=this.querySelector('.ico');
                var open=ico.textContent==='-'; 
                Array.prototype.forEach.call(rows,function(r){
                    r.style.display=open?'none':'';
                });
                ico.textContent=open?'+':'-';
                this.classList.toggle('active');
                "">
                <td><div class='gl'><span class='tog'><span class='ico'>-</span></span>" & _g & "</div></td>"
           & _celdasGrupo &
            IF(
                _mostrarPTD,
                "<td class='ct" & _totalGCls & "'>" & _totalGFmt & "</td>",
                ""
            )

        VAR _esPrimerGrupo = [ord_g] = 1
        VAR _hijos =
            ADDCOLUMNS(
                CALCULATETABLE(
                    FILTER(
                        VALUES( 'origenesdecontabilidad-PL'[SubClassCG] ),
                        NOT ISBLANK( 'origenesdecontabilidad-PL'[SubClassCG] )
                    ),
                    'origenesdecontabilidad-PL'[ClassCG] = _g
                ),
                "ord_h",
                    CALCULATE(
                        MAX('origenesdecontabilidad-PL'[SubClassCG_Order])
                    )
            )

        VAR _countHijos = COUNTROWS(_hijos)

        VAR _filasHijos =
            CONCATENATEX(
                _hijos,
                VAR _h = 'origenesdecontabilidad-PL'[SubClassCG]
                VAR _hid = _gid & "_" & SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(_h," ","_"),"/","_"),"&","_")
                VAR _index =
                    RANKX(
                        _hijos,
                        [ord_h],
                        ,
                        ASC,
                        DENSE
                    )

                -- ============================================================
                -- NIVEL 3: campo de detalle = pozo
                -- ============================================================
                VAR _detalles =
                    ADDCOLUMNS(
                        FILTER(
                            VALUES('origenesdecontabilidad-PL'[nombreproveedor]),
                            NOT ISBLANK('origenesdecontabilidad-PL'[nombreproveedor])
                        ),
                        "montoHijo",
                            VAR _tmp =
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    'origenesdecontabilidad-PL'[ClassCG] = _g,
                                    'origenesdecontabilidad-PL'[SubClassCG] = _h
                                )
                            RETURN ABS(_tmp)
                    )

                VAR _detallesFiltrados =
                    FILTER(
                        _detalles,
                        [montoHijo] <> 0
                    )

                VAR _filasDetalle =
                    CONCATENATEX(
                        _detallesFiltrados,
                        VAR _d = 'origenesdecontabilidad-PL'[nombreproveedor]

                        VAR _celdasDetalle =
                            CONCATENATEX(
                                _columnas,

                                VAR _y = [Anio]
                                VAR _esYTD = [EsYTD]
                                VAR _m = [Mes]

                        VAR _v =
                            IF(
                                _esYTD,

                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    'origenesdecontabilidad-PL'[ClassCG] = _g,
                                    'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                    'origenesdecontabilidad-PL'[nombreproveedor] = _d,
                                    calendariocontable[año] = _y
                                ),

                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    'origenesdecontabilidad-PL'[ClassCG] = _g,
                                    'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                    'origenesdecontabilidad-PL'[nombreproveedor] = _d,
                                    calendariocontable[año] = _y,
                                    calendariocontable[month_en] = _m
                                )
                            )

                                VAR _cls = IF(ISBLANK(_v),"",IF(_v<0," neg",""))
                                VAR _fmt =
                                    IF(ISBLANK(_v),"",
                                        IF(_v<0,
                                            "-" & FORMAT(ROUND(ABS(_v)/1000,0),"#,##0"),
                                            FORMAT(ROUND(_v/1000,0),"#,##0")
                                        )
                                    )

                                RETURN "<td class='"&_cls&"'>"&_fmt&"</td>",
                                "", [Orden]
                            )

                        VAR _totalD =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = _g,
                                'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                'origenesdecontabilidad-PL'[nombreproveedor] = _d
                            )

                        VAR _totalDCls = IF( NOT ISBLANK(_totalD) && _totalD < 0, " neg", "" )
                        VAR _totalDFmt =
                            IF(ISBLANK(_totalD),"",
                                IF(_totalD<0,
                                    "-" & FORMAT(ROUND(ABS(_totalD)/1000,0),"#,##0"),
                                    FORMAT(ROUND(_totalD/1000,0),"#,##0")
                                )
                            )

                        RETURN
                        "<tr class='sh2' data-h='"&_hid&"' style='display:none'>
                            <td style='padding-left:40px'>"&_d&"</td>"
                        & _celdasDetalle &
                        IF(
                            _mostrarPTD,
                            "<td class='ct" & _totalDCls & "'>" & _totalDFmt & "</td>",
                            ""
                        )&"</tr>",
                        "", [montoHijo], DESC
                    )

                VAR _extraClass =
                IF(_esPrimerGrupo && _index = 1, " first-global", "") &
                    IF(_index = 1, " first", "") &
                    IF(_index = _countHijos, " last", "")

                VAR _celdasHijo =
                    CONCATENATEX(
                        _columnas,

                        VAR _y = [Anio]
                        VAR _esYTD = [EsYTD]
                        VAR _m = [Mes]

                VAR _v =
                    IF(
                        _esYTD,

                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG] = _g,
                            'origenesdecontabilidad-PL'[SubClassCG] = _h,
                            calendariocontable[año] = _y
                        ),

                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG] = _g,
                            'origenesdecontabilidad-PL'[SubClassCG] = _h,
                            calendariocontable[año] = _y,
                            calendariocontable[month_en] = _m
                        )
                    )
                        VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                        VAR _fmt = IF( ISBLANK(_v), "", IF( _v < 0, "-" & FORMAT( ROUND( ABS(_v) / 1000, 0 ), "#,##0" ),FORMAT( ROUND( _v / 1000, 0 ), "#,##0" ) ) )
                        RETURN "<td class='" & _cls & "'>" & _fmt & "</td>",
                        "", [Orden]
                    )

                VAR _totalH =
                    CALCULATE(
                        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                        'origenesdecontabilidad-PL'[SubClassCG]  = _h
                    )
                VAR _totalHCls = IF( NOT ISBLANK(_totalH) && _totalH < 0, " neg", "" )
                VAR _totalHFmt = 
                IF(
                    ISBLANK(_totalH),
                    "",
                    IF(
                        _totalH < 0,
                        "-" & FORMAT( ROUND( ABS(_totalH) / 1000, 0 ), "#,##0" ),
                        FORMAT( ROUND( _totalH / 1000, 0 ), "#,##0" )
                    )
                )

                RETURN
                    "<tr class='sh" & _extraClass & "' 
                        data-g='" & _gid & "' 
                        data-h-parent='" & _hid & "' 
                        style='display:table-row'
                        onclick="" 
                            var rows=this.parentNode.querySelectorAll('[data-h=&quot;" & _hid & "&quot;]');
                            var ico=this.querySelector('.ico');
                            var open = ico.textContent==='+'; 

                            Array.prototype.forEach.call(rows,function(r){
                                r.style.display = open ? '' : 'none';
                            });

                            if(ico){
                                ico.textContent = open ? '-' : '+';
                            }
                            this.classList.toggle('active');
                        "">
                        <td>
                            <div class='gl'>
                                <span class='tog'>
                                    <span class='ico'>+</span>
                                </span>" & _h & "
                            </div>
                        </td>"
                        & _celdasHijo
                        & IF(
                            _mostrarPTD,
                            "<td class='ct" & _totalHCls & "'>" & _totalHFmt & "</td>",
                            ""
                        ) 
                        & "</tr>"
                        & _filasDetalle,
                    "",
                    [ord_h]
            )

        VAR _esUltimo = IF( MAXX( _grupos, [ord_g] ) = [ord_g], TRUE(), FALSE() )

        VAR _separador =
            IF(
                NOT _esUltimo,
                "<tr style='height:16px;background:#ffffff;'>
                    <td colspan='99' style='padding:0;background:#ffffff;border:none;'></td>
                </tr>",
                "" 
            )

        RETURN _filasHijos  & _filaGrupo,
        "", [ord_g]
    )

RETURN
    _style &
