VAR _orden = DATATABLE(
    "grp", STRING, "ord", INTEGER,
    {{"Revenue",1},{"DWP",2},{"Operational Result",3},{"Sin Clasificar",4}}
)

VAR _periodos =
    ADDCOLUMNS(
        FILTER(
            SUMMARIZE( calendariocontable, calendariocontable[año], calendariocontable[month_en] ),
            NOT ISBLANK( calendariocontable[month_en] ) &&
            CALCULATE( SUM('origenesdecontabilidad-PL'[amrusd]) ) <> 0
        ),
        "ordMes",
            SWITCH( 
                TRUE(),
                calendariocontable[month_en] = "Jan",1,
                calendariocontable[month_en] = "Feb",2,
                calendariocontable[month_en] = "Mar",3,
                calendariocontable[month_en] = "Apr",4,
                calendariocontable[month_en] = "May",5,
                calendariocontable[month_en] = "Jun",6,
                calendariocontable[month_en] = "Jul",7,
                calendariocontable[month_en] = "Aug",8,
                calendariocontable[month_en] = "Sep",9,
                calendariocontable[month_en] = "Oct",10,
                calendariocontable[month_en] = "Nov",11,
                calendariocontable[month_en] = "Dec",12
            ),
        "ordGlobal",
            calendariocontable[año] * 100 +
            SWITCH(
                TRUE(),
                calendariocontable[month_en] = "Jan",1,
                calendariocontable[month_en] = "Feb",2,
                calendariocontable[month_en] = "Mar",3,
                calendariocontable[month_en] = "Apr",4,
                calendariocontable[month_en] = "May",5,
                calendariocontable[month_en] = "Jun",6,
                calendariocontable[month_en] = "Jul",7,
                calendariocontable[month_en] = "Aug",8,
                calendariocontable[month_en] = "Sep",9,
                calendariocontable[month_en] = "Oct",10,
                calendariocontable[month_en] = "Nov",11,
                calendariocontable[month_en] = "Dec",12
            )
    )

VAR _columnas =
    UNION(
        SELECTCOLUMNS(
            _periodos,
            "Anio", calendariocontable[año],
            "Mes", calendariocontable[month_en],
            "Orden", [ordGlobal],
            "EsYTD", FALSE()
        ),
        SELECTCOLUMNS(
            VALUES(calendariocontable[año]),
            "Anio", calendariocontable[año],
            "Mes", "YTD",
            "Orden", calendariocontable[año] * 100 + 13,
            "EsYTD", TRUE()
        )
    )

VAR _anios =
    ADDCOLUMNS(
        VALUES(calendariocontable[año]),
        "colspanAnio",
            COUNTROWS(
                FILTER(
                    _periodos,
                    calendariocontable[año] = EARLIER(calendariocontable[año])
                )
            ) + 1  -- meses + YTD
    )

VAR _numAnios = COUNTROWS(_anios)
VAR _mostrarPTD = _numAnios > 1

-- ============================================================
-- THEAD: th de año con id, data-year, data-colspan-full,
--        data-colspan-min y onclick para toggle
-- ============================================================
// VAR _thAnios =
//     CONCATENATEX(
//         _anios,
//         VAR _y        = calendariocontable[año]
//         VAR _cFull    = [colspanAnio]   -- meses + YTD
//         VAR _cMin     = 1               -- solo YTD
//         RETURN
//         "<th id='yh-" & _y & "'
//              class='yh'
//              data-year='" & _y & "'
//              data-colspan-full='" & _cFull & "'
//              data-colspan-min='" & _cMin & "'
//              colspan='1'
//              onclick='toggleYear(" & _y & ")'
//              title='Click para expandir / resumir'>" &
//             _y &
//         "</th>",
//         "", calendariocontable[año]
//     )

VAR _thAnios =
    CONCATENATEX(
        _anios,
        VAR _y        = calendariocontable[año]
        VAR _cFull    = [colspanAnio]   -- meses + YTD
        VAR _cMin     = 1               -- solo YTD
        RETURN
            "<th id='yh-" & _y & "'
                class='yh'
                data-year='" & _y & "'
                data-colspan-full='" & _cFull & "'
                data-colspan-min='" & _cMin & "'
                colspan='1'>" &
                _y &
            "</th>",
        "", calendariocontable[año]
    )

-- ============================================================
-- THEAD: th de meses con clase yr-{año} para toggle
-- ============================================================
VAR _thMeses =
    CONCATENATEX(
        _columnas,
        VAR _y    = [Anio]
        VAR _esYTD = [EsYTD]
        RETURN
        "<th" &
            IF( _esYTD,
                " class='ct'",
                " class='month-col yr-" & _y & "' style='display:none;'"
            ) &
        ">" &
            [Mes] &
        "</th>",
        "",
        [Orden]
    )

VAR _thead =
    "<thead>
        <tr>
            <th rowspan='2' style='vertical-align:middle;text-align:center;border-bottom:none;'>Class / Sub-Class</th>"
            & _thAnios &
            IF(
                _mostrarPTD,
                "<th rowspan='2' class='yh ct' style='vertical-align:middle;border-bottom:none;cursor:default;'>PTD</th>",
                ""
            ) &
    "</tr>
    <tr>" & _thMeses & "</tr>
    </thead>"

-- ============================================================
-- GRUPOS
-- ============================================================
VAR _grupos =
    FILTER(
        ADDCOLUMNS(
            FILTER( VALUES( 'origenesdecontabilidad-PL'[ClassCG] ), 
                NOT ISBLANK( 'origenesdecontabilidad-PL'[ClassCG] ) 
                && 'origenesdecontabilidad-PL'[ClassCG] <> "Sin Clasificar"
            ),
            "ord_g", MAXX( FILTER( _orden, [grp] = 'origenesdecontabilidad-PL'[ClassCG] ), [ord] )
        ),
        NOT ISBLANK( [ord_g] )
    )

-- ============================================================
-- FILAS
-- Cambio en td de meses: agregamos class='month-col yr-{año}'
-- para que el toggle los encuentre y los oculte/muestre
-- ============================================================
VAR _filas =
    CONCATENATEX(
        _grupos,
        VAR _g   = 'origenesdecontabilidad-PL'[ClassCG]
        VAR _gid = SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(_g," ","_"),"/","_"),"&","_")

        VAR _celdasGrupo =
            CONCATENATEX(
                _columnas,
                VAR _y     = [Anio]
                VAR _esYTD = [EsYTD]
                VAR _m     = [Mes]

                VAR _baseG =
                    SUMX(
                        FILTER(
                            VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                            NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                        ),
                        IF(
                            _esYTD,
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG]=_g,
                                calendariocontable[año]=_y
                            ),
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG]=_g,
                                calendariocontable[año]=_y,
                                calendariocontable[month_en]=_m
                            )
                        )
                    )

                VAR _rev_m =
                    SUMX(
                        FILTER(
                            VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                            NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                        ),
                        IF(
                            _esYTD,
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                                calendariocontable[año]=_y
                            ),
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                                calendariocontable[año]=_y,
                                calendariocontable[month_en]=_m
                            )
                        )
                    )

                VAR _dwp_m =
                    SUMX(
                        FILTER(
                            VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                            NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                        ),
                        IF(
                            _esYTD,
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                                calendariocontable[año]=_y
                            ),
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                                calendariocontable[año]=_y,
                                calendariocontable[month_en]=_m
                            )
                        )
                    )

                VAR _v =
                    SWITCH(
                        TRUE(),
                        _g = "DWP",               _baseG + _rev_m,
                        _g = "Operational Result", _baseG + _dwp_m + _rev_m,
                        _baseG
                    )

                VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                VAR _fmt =
                    IF( ISBLANK(_v), "",
                        IF( _v < 0,
                            "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                            FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                        )
                    )
                -- Meses: ocultos por default + clase para toggle
                -- YTD:   visible siempre, clase ct
                RETURN
                    IF(
                        _esYTD,
                        "<td class='ct" & _cls & "'>" & _fmt & "</td>",
                        "<td class='month-col yr-" & _y & _cls & "' style='display:none;'>" & _fmt & "</td>"
                    ),
                "",
                [Orden]
            )

        VAR _baseGTotal =
            SUMX(
                FILTER(
                    VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                    NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                ),
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    'origenesdecontabilidad-PL'[ClassCG] = _g
                )
            )

        VAR _revTotal =
            SUMX(
                FILTER(
                    VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                    NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                ),
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    'origenesdecontabilidad-PL'[ClassCG] = "Revenue"
                )
            )

        VAR _dwpTotal =
            SUMX(
                FILTER(
                    VALUES('origenesdecontabilidad-PL'[SubClassCG]),
                    NOT ISBLANK('origenesdecontabilidad-PL'[SubClassCG])
                ),
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                )
            )

        VAR _totalG =
            SWITCH(
                TRUE(),
                _g = "DWP",               _baseGTotal + _revTotal,
                _g = "Operational Result", _baseGTotal + _dwpTotal + _revTotal,
                _baseGTotal
            )

        VAR _totalGCls = IF( NOT ISBLANK(_totalG) && _totalG < 0, " neg", "" )
        VAR _totalGFmt =
            IF( ISBLANK(_totalG), "",
                IF( _totalG < 0,
                    "-" & FORMAT( ROUND( ABS(_totalG)/1000, 0 ), "#,##0" ),
                    FORMAT( ROUND( _totalG/1000, 0 ), "#,##0" )
                )
            )

        VAR _filaGrupo =
            "<tr class='gh' 
            onclick=""var rows=this.parentNode.querySelectorAll('[data-g=&quot;" & _gid & "&quot;]');
                var ico=this.querySelector('.ico');
                var open=ico.textContent==='-'; 
                Array.prototype.forEach.call(rows,function(r){
                    r.style.display=open?'none':'';
                });
                ico.textContent=open?'+':'-';
                this.classList.toggle('active');
                "">
                <td><div class='gl'><span class='tog'><span class='ico'>-</span></span>" & _g & "</div></td>"
           & _celdasGrupo &
            IF(
                _mostrarPTD,
                "<td class='ct" & _totalGCls & "'>" & _totalGFmt & "</td>",
                ""
            ) &
            "</tr>"

        VAR _esPrimerGrupo = [ord_g] = 1
        VAR _hijos =
            ADDCOLUMNS(
                CALCULATETABLE(
                    FILTER(
                        VALUES( 'origenesdecontabilidad-PL'[SubClassCG] ),
                        NOT ISBLANK( 'origenesdecontabilidad-PL'[SubClassCG] )
                    ),
                    'origenesdecontabilidad-PL'[ClassCG] = _g
                ),
                "ord_h",
                    CALCULATE(
                        MAX('origenesdecontabilidad-PL'[SubClassCG_Order])
                    )
            )

        VAR _countHijos = COUNTROWS(_hijos)

        VAR _filasHijos =
            CONCATENATEX(
                _hijos,
                VAR _h   = 'origenesdecontabilidad-PL'[SubClassCG]
                VAR _hid = _gid & "_" & SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(_h," ","_"),"/","_"),"&","_")
                VAR _index = RANKX( _hijos, [ord_h], , ASC, DENSE )

                VAR _detalles =
                    ADDCOLUMNS(
                        FILTER(
                            VALUES('origenesdecontabilidad-PL'[pozo]),
                            NOT ISBLANK('origenesdecontabilidad-PL'[pozo])
                        ),
                        "montoHijo",
                            ABS( CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = _g,
                                'origenesdecontabilidad-PL'[SubClassCG] = _h
                            ))
                    )

                VAR _detallesFiltrados = FILTER( _detalles, [montoHijo] <> 0 )

                VAR _filasDetalle =
                    CONCATENATEX(
                        _detallesFiltrados,
                        VAR _d = 'origenesdecontabilidad-PL'[pozo]

                        VAR _celdasDetalle =
                            CONCATENATEX(
                                _columnas,
                                VAR _y     = [Anio]
                                VAR _esYTD = [EsYTD]
                                VAR _m     = [Mes]

                                VAR _v =
                                    IF(
                                        _esYTD,
                                        CALCULATE(
                                            SUM('origenesdecontabilidad-PL'[amrusd]),
                                            'origenesdecontabilidad-PL'[ClassCG] = _g,
                                            'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                            'origenesdecontabilidad-PL'[pozo] = _d,
                                            calendariocontable[año] = _y
                                        ),
                                        CALCULATE(
                                            SUM('origenesdecontabilidad-PL'[amrusd]),
                                            'origenesdecontabilidad-PL'[ClassCG] = _g,
                                            'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                            'origenesdecontabilidad-PL'[pozo] = _d,
                                            calendariocontable[año] = _y,
                                            calendariocontable[month_en] = _m
                                        )
                                    )

                                VAR _cls = IF(ISBLANK(_v),"",IF(_v<0," neg",""))
                                VAR _fmt =
                                    IF(ISBLANK(_v),"",
                                        IF(_v<0,
                                            "-" & FORMAT(ROUND(ABS(_v)/1000,0),"#,##0"),
                                            FORMAT(ROUND(_v/1000,0),"#,##0")
                                        )
                                    )
                                RETURN
                                    IF(
                                        _esYTD,
                                        "<td class='ct" & _cls & "'>" & _fmt & "</td>",
                                        "<td class='month-col yr-" & _y & _cls & "' style='display:none;'>" & _fmt & "</td>"
                                    ),
                                "", [Orden]
                            )

                        VAR _totalD =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = _g,
                                'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                'origenesdecontabilidad-PL'[pozo] = _d
                            )
                        VAR _totalDCls = IF( NOT ISBLANK(_totalD) && _totalD < 0, " neg", "" )
                        VAR _totalDFmt =
                            IF(ISBLANK(_totalD),"",
                                IF(_totalD<0,
                                    "-" & FORMAT(ROUND(ABS(_totalD)/1000,0),"#,##0"),
                                    FORMAT(ROUND(_totalD/1000,0),"#,##0")
                                )
                            )

                        RETURN
                        "<tr class='sh2' data-h='" & _hid & "' style='display:none'>
                            <td style='padding-left:40px'>" & _d & "</td>"
                        & _celdasDetalle &
                        IF(
                            _mostrarPTD,
                            "<td class='ct" & _totalDCls & "'>" & _totalDFmt & "</td>",
                            ""
                        ) & "</tr>",
                        "", [montoHijo], DESC
                    )

                VAR _extraClass =
                    IF(_esPrimerGrupo && _index = 1, " first-global", "") &
                    IF(_index = 1, " first", "") &
                    IF(_index = _countHijos, " last", "")

                VAR _celdasHijo =
                    CONCATENATEX(
                        _columnas,
                        VAR _y     = [Anio]
                        VAR _esYTD = [EsYTD]
                        VAR _m     = [Mes]

                        VAR _v =
                            IF(
                                _esYTD,
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    'origenesdecontabilidad-PL'[ClassCG] = _g,
                                    'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                    calendariocontable[año] = _y
                                ),
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    'origenesdecontabilidad-PL'[ClassCG] = _g,
                                    'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                    calendariocontable[año] = _y,
                                    calendariocontable[month_en] = _m
                                )
                            )

                        VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                        VAR _fmt =
                            IF( ISBLANK(_v), "",
                                IF( _v < 0,
                                    "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                                    FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                                )
                            )
                        RETURN
                            IF(
                                _esYTD,
                                "<td class='ct" & _cls & "'>" & _fmt & "</td>",
                                "<td class='month-col yr-" & _y & _cls & "' style='display:none;'>" & _fmt & "</td>"
                            ),
                        "", [Orden]
                    )

                VAR _totalH =
                    CALCULATE(
                        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                    )
                VAR _totalHCls = IF( NOT ISBLANK(_totalH) && _totalH < 0, " neg", "" )
                VAR _totalHFmt = 
                    IF( ISBLANK(_totalH), "",
                        IF( _totalH < 0,
                            "-" & FORMAT( ROUND( ABS(_totalH)/1000, 0 ), "#,##0" ),
                            FORMAT( ROUND( _totalH/1000, 0 ), "#,##0" )
                        )
                    )

                RETURN
                    "<tr class='sh" & _extraClass & "' 
                        data-g='" & _gid & "' 
                        data-h-parent='" & _hid & "' 
                        style='display:table-row'
                        onclick="" 
                            var rows=this.parentNode.querySelectorAll('[data-h=&quot;" & _hid & "&quot;]');
                            var ico=this.querySelector('.ico');
                            var open = ico.textContent==='+'; 
                            Array.prototype.forEach.call(rows,function(r){
                                r.style.display = open ? '' : 'none';
                            });
                            if(ico){ ico.textContent = open ? '-' : '+'; }
                            this.classList.toggle('active');
                        "">
                        <td>
                            <div class='gl'>
                                <span class='tog'><span class='ico'>+</span></span>" & _h & "
                            </div>
                        </td>"
                    & _celdasHijo
                    & IF(
                        _mostrarPTD,
                        "<td class='ct" & _totalHCls & "'>" & _totalHFmt & "</td>",
                        ""
                    ) 
                    & "</tr>"
                    & _filasDetalle,
                "",
                [ord_h]
            )

        RETURN _filasHijos & _filaGrupo,
        "", [ord_g]
    )

-- ============================================================
-- TOOLBAR  (mismos iconos que MatrizPozos via [PL_ImgUp] / [PL_ImgExpand])
-- ============================================================
VAR _toolbar =
"<div class='toolbar'>

    <button class='tb-btn'
        onclick='collapseAllYears()'
        title='Resumir meses'>
        <img src='" & [PL_ImgUp] & "'
             style='width:35px;transition:transform 0.2s ease;cursor:pointer;'
             onmouseover='this.style.transform=""scale(1.15)"";'
             onmouseout='this.style.transform=""scale(1)"";'
        />
    </button>

    <button class='tb-btn'
        onclick='expandAllYears()'
        title='Expandir meses'>
        <img src='" & [PL_ImgExpand] & "'
             style='width:30px;transform:rotate(180deg);transition:transform 0.2s ease;cursor:pointer;'
             onmouseover='this.style.transform=""rotate(180deg) scale(1.15)"";'
             onmouseout='this.style.transform=""rotate(180deg) scale(1)"";'
        />
    </button>

</div>"

RETURN
    _style &
    _script &
    "<div class='wrap'>" &
        _toolbar &
        "<div class='tw'>
            <table>" &
            _thead &
            "<tbody>" & _filas & "</tbody>" &
            "</table>
        </div>
    </div>"","errorMessage":null,"hidden":false,"references":{"unrecognizedReferences":false,"measures":[{"schema":"","entity":"medidas","name":"PL_ImgUp"},{"schema":"","entity":"medidas","name":"PL_ImgExpand"}]},"formulaOverride":null,"formatInformation":{"formatString":"G","format":"General","thousandSeparator":false,"currencyFormat":null,"dateTimeCustomFormat":null}},{"name":"HTML_FinancialTable_Prov_2","dataType":3,"expression":"
VAR _style = "<style>
*{box-sizing:border-box;margin:0;padding:0;}

.wrap{
    position:relative;
    width:100%;
    overflow:visible;
    padding-top:35px;
}

.tw{
    font-family: Segoe UI SemiBold, Arial, sans-serif;
    font-size:14px;
    overflow-x:auto;
    width:100%;
} 

table{
    width:auto;
    border-collapse:separate;
    border-spacing: 1.5px;
    background:rgba(0,0,0,0.08);
    min-width:auto;
    table-layout: fixed;
}

th{
    background:#1A1A1A;
    color:#FFF;
    padding:5px 8px;
    text-align:center;
    font-weight:600;
    font-size:15px;
    white-space:nowrap;
    border-right:0px solid #CCCCCC;
    border-bottom:0px solid #CCCCCC;
    border-top:0px solid #CCCCCC;
}

th:first-child{
    text-align:center;
    width:30px;
}
td:first-child{
    width: 60px;
}

th.yh{
    text-align:center;
    background:#1A1A1A;
    /* cursor:pointer; */ /* Esto es cuando se quiere añadir el expandir desde el año */
    user-select:none;  /* Esto es cuando se quiere añadir el expandir desde el año */
}

/* Esto es cuando se quiere añadir el expandir desde el año */
/*  th.yh:hover{
    background:#333;
} */

th:not(:first-child),
td:not(:first-child){
    width: 90px;
    min-width: 90px;
}

th.ct,
td.ct{
   width: 90px;
   min-width: 90px;
}

td{
    padding:4px 4px;
    text-align:center;
    border-bottom:0px solid #E5E5E5;
    border-right:0px solid #E5E5E5;
    white-space:nowrap;
}

td:first-child{
    text-align:left;
    padding-left:10px;
    width:100px;
}

tr.gh td{
    background:#CCCCCC;
    color:#000000;
    font-weight:500;
    font-size:14.5px;
    cursor:pointer;
    border-top:1px solid #CCCCCC;
}

tr.gh td{
    border-top:0px solid #ffffff;
}

tr.sh td{
