                VAR _hid = _gid & "_" & SUBSTITUTE(SUBSTITUTE(SUBSTITUTE(_h," ","_"),"/","_"),"&","_")
                VAR _index = RANKX( _hijos, [ord_h], , ASC, DENSE )

                VAR _detalles =
