                                    IF(
                                        _esYTD,
                                        CALCULATE(
                                            SUM('origenesdecontabilidad-PL'[amrusd]),
                                            'origenesdecontabilidad-PL'[ClassCG] = _g,
                                            'origenesdecontabilidad-PL'[SubClassCG] = _h,
