                                            'origenesdecontabilidad-PL'[ClassCG] = _g,
                                            'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                            'origenesdecontabilidad-PL'[nombreproveedor] = _d,
                                            calendariocontable[año] = _y,
                                            calendariocontable[month_en] = _m
                                        )
                                    )

                                VAR _cls = IF(ISBLANK(_v),"",IF(_v<0," neg",""))
                                VAR _fmt =
                                    IF(ISBLANK(_v),"",
