                                            "-" & FORMAT(ROUND(ABS(_v)/1000,0),"#,##0"),
                                            FORMAT(ROUND(_v/1000,0),"#,##0")
                                        )
                                    )
                                RETURN
                                    IF(
                                        _esYTD,
                                        "<td class='ct" & _cls & "'>" & _fmt & "</td>",
                                        "<td class='month-col yr-" & _y & _cls & "' style='display:none;'>" & _fmt & "</td>"
