                                "<td class='month-col yr-" & _y & _cls & "' style='display:none;'>" & _fmt & "</td>"
                            ),
                        "", [Orden]
                    )

                VAR _totalH =
                    CALCULATE(
                        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                    )
                VAR _totalHCls = IF( NOT ISBLANK(_totalH) && _totalH < 0, " neg", "" )
                VAR _totalHFmt = 
                    IF( ISBLANK(_totalH), "",
                        IF( _totalH < 0,
                            "-" & FORMAT( ROUND( ABS(_totalH)/1000, 0 ), "#,##0" ),
                            FORMAT( ROUND( _totalH/1000, 0 ), "#,##0" )
