VAR _NumYears =
    COUNTROWS(_aniosBase)

VAR _periodosBase =
    ADDCOLUMNS(
        FILTER(
            SUMMARIZE(
                calendariocontable,
                calendariocontable[año],
                calendariocontable[month_en]
            ),
            NOT ISBLANK( calendariocontable[año] )
            && NOT ISBLANK( calendariocontable[month_en] )
            && CALCULATE( COUNTROWS( 'origenesdecontabilidad-PL' ) ) > 0
        ),
        "ord_y", calendariocontable[año],
        "ord_m",
            SWITCH( TRUE(),
                calendariocontable[month_en]="Jan",1, calendariocontable[month_en]="Feb",2,
                calendariocontable[month_en]="Mar",3, calendariocontable[month_en]="Apr",4,
                calendariocontable[month_en]="May",5, calendariocontable[month_en]="Jun",6,
                calendariocontable[month_en]="Jul",7, calendariocontable[month_en]="Aug",8,
                calendariocontable[month_en]="Sep",9, calendariocontable[month_en]="Oct",10,
                calendariocontable[month_en]="Nov",11,calendariocontable[month_en]="Dec",12
            )
    )

-- ============================================================
-- dataareaidS ordenados por valor absoluto DESC
-- ============================================================
VAR _enableProviderTooltip = TRUE() //Habilitar o deshabilitar tooltip
VAR _enabledataareaidThreshold = TRUE() -- Se activa o no el valor mínimo
VAR _dataareaidThreshold = 'Min - USD'[Valor de Min - USD] --VALOR minimo del total de Operationaal Result
VAR _dataareaids =
    ADDCOLUMNS(
        FILTER(
            FILTER(
                VALUES( 'origenesdecontabilidad-PL'[dataareaid] ),
                NOT ISBLANK( 'origenesdecontabilidad-PL'[dataareaid] )
            ),
            VAR _totaldataareaid =
            CALCULATE(

                SUM( 'origenesdecontabilidad-PL'[amrusd] ),

                'origenesdecontabilidad-PL'[ClassCG] IN {
                    "Revenue",
                    "DWP",
                    "Operational Result"
                }
            )
            RETURN
            NOT ISBLANK( _totaldataareaid ) && _totaldataareaid <> 0
            && IF(
                _enabledataareaidThreshold,
                ABS(_totaldataareaid) >= _dataareaidThreshold,
                TRUE()
            )
        ),
        "ord_p",
            ABS(
                CALCULATE(
                    SUM( 'origenesdecontabilidad-PL'[amrusd] )
                )
            )
    )
 VAR _NumDataAreaIds =
    COUNTROWS(_dataareaids)
-- ============================================================
-- ANIOS Y MESES POR dataareaid (solo periodos con datos para ese dataareaid)
-- ============================================================
VAR _dataareaidAnio =
    FILTER(
        GENERATE(
            _dataareaids,
            VAR _p_inner = 'origenesdecontabilidad-PL'[dataareaid]
            RETURN
                ADDCOLUMNS(
                    _aniosBase,
                    "tiene_dato",
                        CALCULATE(
                            SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                            'origenesdecontabilidad-PL'[dataareaid] = _p_inner
                        )
                )
        ),
        NOT ISBLANK( [tiene_dato] ) && [tiene_dato] <> 0
    )

VAR _dataareaidPeriodo =
    FILTER(
        GENERATE(
            _dataareaids,
            VAR _p_inner = 'origenesdecontabilidad-PL'[dataareaid]
            RETURN
                ADDCOLUMNS(
                    _periodosBase,
                    "tiene_dato",
                        CALCULATE(
                            SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                            'origenesdecontabilidad-PL'[dataareaid] = _p_inner
                        )
                )
        ),
        NOT ISBLANK( [tiene_dato] ) && [tiene_dato] <> 0
    )

-- ============================================================
-- ENCABEZADO FILA 1: nombres de dataareaid con colspan
-- ============================================================
VAR _thdataareaids =
    CONCATENATEX(
        _dataareaids,
        VAR _p = 'origenesdecontabilidad-PL'[dataareaid]
        VAR _aniosdataareaid =
            FILTER( _dataareaidAnio, 'origenesdecontabilidad-PL'[dataareaid] = _p )
        VAR _numY =
            COUNTROWS( _aniosdataareaid )
        VAR _numPeriodos =
            SUMX(
                _aniosdataareaid,
                VAR _y = calendariocontable[año]
                VAR _cntMes =
