-- ============================================================
-- ORDEN DE CLASES
-- ============================================================
VAR _ordenClass = DATATABLE(
    "grp", STRING, "ord", INTEGER,
    {{"Revenue",1},{"DWP",2},{"Operational Result",3},{"Sin Clasificar",4}}
)
-- ============================================================
-- CLASES GLOBALES
-- ============================================================
// VAR _grupos =
//     ADDCOLUMNS(
//         FILTER(
//             VALUES( 'origenesdecontabilidad-PL'[ClassCG] ),
//             NOT ISBLANK( 'origenesdecontabilidad-PL'[ClassCG] )
//         ),
//         "ord_g",
//             MAXX( FILTER( _ordenClass, [grp] = 'origenesdecontabilidad-PL'[ClassCG] ), [ord] )
//     )

    VAR _grupos =
    FILTER(
        ADDCOLUMNS(
            FILTER( VALUES( 'origenesdecontabilidad-PL'[ClassCG] ), 
            NOT ISBLANK( 'origenesdecontabilidad-PL'[ClassCG] ) 
             && 'origenesdecontabilidad-PL'[ClassCG] <> "Sin Clasificar"
            ),"ord_g", MAXX( FILTER( _ordenClass, [grp] = 'origenesdecontabilidad-PL'[ClassCG] ), [ord] )
        ),
        NOT ISBLANK( [ord_g] )
    )

-- ============================================================
-- CONSTRUCCIÓN DE FILAS
-- ============================================================
VAR _filas =
    CONCATENATEX(
        _grupos,
        VAR _g   = 'origenesdecontabilidad-PL'[ClassCG]
        VAR _gid = SUBSTITUTE( SUBSTITUTE( SUBSTITUTE( _g, " ", "_" ), "/", "_" ), "&", "_" )
        VAR _grandTotal =
            SWITCH(
                TRUE(),

                _g = "Revenue",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] = "Revenue"
                    ),

                _g = "DWP",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP"}
                    ),

                _g = "Operational Result",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] IN {
                            "Revenue",
                            "DWP",
                            "Operational Result"
                        }
                    )
            )

        VAR _grandFmt =
            IF(
                ISBLANK(_grandTotal),
                "",
                IF(
                    _grandTotal < 0,
                    "-" & FORMAT( ROUND( ABS(_grandTotal)/1000, 0 ), "#,##0" ),
                    FORMAT( ROUND( _grandTotal/1000, 0 ), "#,##0" )
                )
            )

        VAR _grandCls =
            IF( NOT ISBLANK(_grandTotal) && _grandTotal < 0, " neg", "" )

        -- Celdas del grupo: total del dataareaid, luego anios y meses al expandir
        VAR _celdasGrupo =
            CONCATENATEX(
                _dataareaids,
                VAR _p = 'origenesdecontabilidad-PL'[dataareaid]
                VAR _aniosdataareaid = FILTER( _dataareaidAnio, 'origenesdecontabilidad-PL'[dataareaid] = _p )
                VAR _rankdataareaid = RANKX( _dataareaids, [ord_p], , DESC, DENSE )
                VAR _tdsPeriodos =
                    CONCATENATEX(
                        _aniosdataareaid,
                        VAR _y = calendariocontable[año]
                        VAR _rankAnio = RANKX( _aniosdataareaid, [ord_y], , ASC, DENSE )
                        VAR _mesesdataareaidAnio =
                            FILTER(
                                _dataareaidPeriodo,
                                'origenesdecontabilidad-PL'[dataareaid] = _p
                                && calendariocontable[año] = _y
                            )
                        VAR _tdsMeses =
                            CONCATENATEX(
                                _mesesdataareaidAnio,
                                VAR _m = calendariocontable[month_en]
                                VAR _revenue =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[dataareaid] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                                        calendariocontable[año] = _y,
                                        calendariocontable[month_en] = _m
                                    )

                                VAR _dwp =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[dataareaid] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                                        calendariocontable[año] = _y,
                                        calendariocontable[month_en] = _m
                                    )

                                VAR _op =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[dataareaid] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = "Operational Result",
                                        calendariocontable[año] = _y,
                                        calendariocontable[month_en] = _m
                                    )

                                VAR _v =
                                    SWITCH(
                                        TRUE(),
                                        _g = "Revenue",
                                            _revenue,
                                        _g = "DWP",
                                            _revenue + _dwp,
                                        _g = "Operational Result",
                                            _revenue + _dwp + _op,
                                        BLANK()
                                    )
                                VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                                VAR _fmt =
                                    IF( ISBLANK(_v), "",
                                        IF( _v < 0,
                                            "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                                            FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                                        )
                                    )
                                RETURN
                                    "<td style='display:none;' class='data month p" & _rankdataareaid & " py" & _rankdataareaid & "_" & _rankAnio & _cls & "'>" & _fmt & "</td>",
                                "", [ord_m], ASC
                            )

                        VAR _revYear =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[dataareaid] = _p,
                                'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                                calendariocontable[año] = _y
                            )

                        VAR _dwpYear =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[dataareaid] = _p,
                                'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                                calendariocontable[año] = _y
                            )

                        VAR _opYear =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[dataareaid] = _p,
                                'origenesdecontabilidad-PL'[ClassCG] = "Operational Result",
                                calendariocontable[año] = _y
                            )

                        VAR _yearTotal =
                            SWITCH(
                                TRUE(),
                                _g = "Revenue", _revYear,
                                _g = "DWP", _revYear + _dwpYear,
                                _g = "Operational Result", _revYear + _dwpYear + _opYear,
                                BLANK()
                            )
                        VAR _fmtYear =
                            IF( ISBLANK(_yearTotal), "",
                                IF( _yearTotal < 0,
                                    "-" & FORMAT( ROUND( ABS(_yearTotal)/1000, 0 ), "#,##0" ),
                                    FORMAT( ROUND( _yearTotal/1000, 0 ), "#,##0" )
                                )
                            )
                        VAR _clsYear = IF( ISBLANK(_yearTotal), "", IF(_yearTotal < 0, " neg", "") )
                        RETURN
                            _tdsMeses &
                            "<td style='display:none;' class='total year-total p" & _rankdataareaid & " ytp" & _rankdataareaid & " py" & _rankdataareaid & "_" & _rankAnio & _clsYear & "'>" &
                                _fmtYear &
                            "</td>",
                        "", [ord_y], ASC
                    )

                   VAR _revTotal =
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[dataareaid] = _p,
                            'origenesdecontabilidad-PL'[ClassCG] = "Revenue"
                        )

                    VAR _dwpTotal =
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[dataareaid] = _p,
                            'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                        )

                    VAR _opTotal =
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[dataareaid] = _p,
                            'origenesdecontabilidad-PL'[ClassCG] = "Operational Result"
                        )

                    VAR _totaldataareaid =
                        SWITCH(
                            TRUE(),
                            _g = "Revenue",_revTotal,
                            _g = "DWP",_revTotal + _dwpTotal,
                            _g = "Operational Result",_revTotal + _dwpTotal + _opTotal,
                            BLANK()
                        )

                VAR _fmtTotal =
                    IF( ISBLANK(_totaldataareaid), "",
                        IF( _totaldataareaid < 0,
                            "-" & FORMAT( ROUND( ABS(_totaldataareaid)/1000, 0 ), "#,##0" ),
                            FORMAT( ROUND( _totaldataareaid/1000, 0 ), "#,##0" )
                        )
                    )
                VAR _clsTotal =
                    IF(
                        ISBLANK(_totaldataareaid),
                        "",IF(_totaldataareaid < 0, " neg", "")
                    )

            RETURN

                _tdsPeriodos &
                IF(
                    _NumYears > 1,

                    "<td
                        style='display:none;'
                        class='total company-total p" & _rankdataareaid &
                        " ctp" & _rankdataareaid &
                        _clsTotal &
                        "'>" &
                        _fmtTotal &
                    "</td>",

                    ""
                ) &

                "<td
                    class='total dataareaid-total pt" & _rankdataareaid &
                    _clsTotal &
                    "'>" &
                    _fmtTotal &
                "</td>",
                "", [ord_p], DESC
            )

        VAR _filaGrupo =
            "<tr class='gh'
                onclick=""var rows=this.parentNode.querySelectorAll('[data-g=&quot;" & _gid & "&quot;]');
                    var ico=this.querySelector('.ico');
                    var open=ico.textContent==='-';
                    Array.prototype.forEach.call(rows,function(r){ r.style.display=open?'none':''; });
                    ico.textContent=open?'+':'-';
                    this.classList.toggle('active');
                "">
                <td class='sticky-col'><div class='gl'><span class='tog'><span class='ico'>-</span></span>" & _g & "</div></td>"
            & _celdasGrupo &
            IF(
                _NumDataAreaIds > 1,

                "<td class='grandtotal" & _grandCls & "'>" &
                    _grandFmt &
                "</td>",

                ""
            )&
            "</tr>"

        -- SubClases
        VAR _hijos =
            ADDCOLUMNS(
                FILTER(
                    CALCULATETABLE(
                        VALUES( 'origenesdecontabilidad-PL'[SubClassCG] ),
                        'origenesdecontabilidad-PL'[ClassCG] = _g
                    ),
                    NOT ISBLANK( 'origenesdecontabilidad-PL'[SubClassCG] )
                ),
                "ord_h",
                    CALCULATE( MAX( 'origenesdecontabilidad-PL'[SubClassCG_Order] ) )
            )

        VAR _countHijos = COUNTROWS( _hijos )
        VAR _filasHijos =
            CONCATENATEX(
                _hijos,
                VAR _h      = 'origenesdecontabilidad-PL'[SubClassCG]
                VAR _providersBase =
                    FILTER(

                        ADDCOLUMNS(
                            SUMMARIZE(
                                FILTER(
                                    'origenesdecontabilidad-PL',
                                    'origenesdecontabilidad-PL'[ClassCG] = _g &&
                                    'origenesdecontabilidad-PL'[SubClassCG] = _h
                                ),

                                'origenesdecontabilidad-PL'[nombreproveedor]
                            ),

                            "amt",
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd])
                                ),

                            "abs_amt",
                                ABS(
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd])
                                    )
                                )
                        ),
                        [amt] <> 0
                    )
               VAR _topProvidersTable =
                TOPN(
                    10,
                    _providersBase,
                    [abs_amt], DESC
                )

                VAR _providerTooltip =
                CONCATENATEX(
                    _topProvidersTable,

                    'origenesdecontabilidad-PL'[nombreproveedor]
                        & ":::"
                        & FORMAT( ROUND([amt] / 1000, 0), "#,##0" ),

                    "|",

                    [abs_amt], DESC
                )

                VAR _indexH = RANKX( _hijos, [ord_h], , ASC, DENSE )
                VAR _celdasHijo =
                    CONCATENATEX(
                        _dataareaids,
                        VAR _p = 'origenesdecontabilidad-PL'[dataareaid]
                        VAR _aniosdataareaid = FILTER( _dataareaidAnio, 'origenesdecontabilidad-PL'[dataareaid] = _p )
                        VAR _rankdataareaid = RANKX( _dataareaids, [ord_p], , DESC, DENSE )
                        VAR _tdsPeriodos =
                            CONCATENATEX(
                                _aniosdataareaid,
                                VAR _y = calendariocontable[año]
                                VAR _rankAnio = RANKX( _aniosdataareaid, [ord_y], , ASC, DENSE )
                                VAR _mesesdataareaidAnio =
                                    FILTER(
                                        _dataareaidPeriodo,
                                        'origenesdecontabilidad-PL'[dataareaid] = _p
                                        && calendariocontable[año] = _y
                                    )
                                VAR _tdsMeses =
                                    CONCATENATEX(
                                        _mesesdataareaidAnio,
                                        VAR _m = calendariocontable[month_en]
                                        VAR _v =
                                            CALCULATE(
                                                SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                                                'origenesdecontabilidad-PL'[dataareaid]       = _p,
                                                'origenesdecontabilidad-PL'[ClassCG]    = _g,
                                                'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                                calendariocontable[año] = _y,
                                                calendariocontable[month_en] = _m
                                            )
                                        VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                                        VAR _fmt =
                                            IF( ISBLANK(_v), "",
                                                IF( _v < 0,
                                                    "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                                                    FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                                                )
                                            )
                                        RETURN
                                            "<td style='display:none;' class='data month p" & _rankdataareaid & " py" & _rankdataareaid & "_" & _rankAnio & _cls & "'>" & _fmt & "</td>",
                                        "", [ord_m], ASC
                                    )

                                VAR _yearTotal =
                                    CALCULATE(
                                        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                                        'origenesdecontabilidad-PL'[dataareaid]       = _p,
                                        'origenesdecontabilidad-PL'[ClassCG]    = _g,
                                        'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                        calendariocontable[año] = _y
                                    )
                                VAR _fmtYear =
                                    IF( ISBLANK(_yearTotal), "",
                                        IF( _yearTotal < 0,
                                            "-" & FORMAT( ROUND( ABS(_yearTotal)/1000, 0 ), "#,##0" ),
                                            FORMAT( ROUND( _yearTotal/1000, 0 ), "#,##0" )
                                        )
                                    )
                                VAR _clsYear =
                                    IF( ISBLANK(_yearTotal), "", IF(_yearTotal < 0, " neg", "") )
                                RETURN
                                    _tdsMeses &
                                    "<td style='display:none;' class='total year-total p" & _rankdataareaid & " ytp" & _rankdataareaid & " py" & _rankdataareaid & "_" & _rankAnio & _clsYear & "'>" &
                                        _fmtYear &
                                    "</td>",
                                "", [ord_y], ASC
                            )

                        VAR _totaldataareaid =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[dataareaid] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                                    )
                        VAR _fmtTotal =
                            IF( ISBLANK(_totaldataareaid), "",
                                IF( _totaldataareaid < 0,
                                    "-" & FORMAT( ROUND( ABS(_totaldataareaid)/1000, 0 ), "#,##0" ),
                                    FORMAT( ROUND( _totaldataareaid/1000, 0 ), "#,##0" )
                                )
                            )
                        VAR _clsTotal =
                            IF(
                                ISBLANK(_totaldataareaid),
                                "",
                                IF(_totaldataareaid < 0, " neg", "")
                            )
                    RETURN

                        _tdsPeriodos &
                        IF(
                            _NumYears > 1,

                            "<td
                                style='display:none;'
                                class='total company-total p" & _rankdataareaid &
                                " ctp" & _rankdataareaid &
                                _clsTotal &
                                "'>" &
                                _fmtTotal &
                            "</td>",

                            ""
                        ) &

                        "<td
                            class='total dataareaid-total pt" & _rankdataareaid &
                            _clsTotal &
                            "'>" &
                            _fmtTotal &
                        "</td>",
                        "", [ord_p], DESC
                    )

                VAR _esPrimerGrupo = [ord_g] = 1

                VAR _extraH =
                    IF( _esPrimerGrupo && _indexH = 1, " first-global", "" ) &
                    IF( _indexH = 1, " first", "" ) &
                    IF( _indexH = _countHijos, " last", "" )

                VAR _grandSub =
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                    )

                VAR _grandSubFmt =
                    IF(
                        ISBLANK(_grandSub),
                        "",
                        IF(
                            _grandSub < 0,
                            "-" & FORMAT( ROUND( ABS(_grandSub)/1000 , 0 ), "#,##0" ),
                            FORMAT( ROUND( _grandSub/1000 , 0 ), "#,##0" )
                        )
                    )

                VAR _grandSubCls =
                    IF(
                        ISBLANK(_grandSub),
                        "",
                        IF(_grandSub < 0, " neg", "")
                    )



        RETURN
            "<tr class='sh" & _extraH & "' data-g='" & _gid & "' style='display:table-row'>
                <td class='sticky-col subclass-cell'

                data-tip='" & _providerTooltip & "'

                " & IF(
                    _enableProviderTooltip,

                    "onclick='showProviderTooltip(this,event)'
                    onmouseleave='hideProviderTooltip()'",

                    ""
                ) & ">

                <div class='gl'>
                    <span style='width:20px;display:inline-block;'></span>" & _h & "
                </div>
                </td>"

            & _celdasHijo &

            IF(
                _NumDataAreaIds > 1,

                "<td class='grandtotal " & _grandSubCls & "'>" &
                    _grandSubFmt &
                "</td>",

                ""
            ) &

            "</tr>","", [ord_h]
            )



        --RETURN _filaGrupo & _filasHijos, --se expande hacia abajo
        RETURN _filasHijos & _filaGrupo, -- se expande hacia arriba
        "", [ord_g]
    )


VAR _script = 
"
<script>

function setdataareaidState(rank, level) {
    var p = 'p' + rank;
    var hp = document.getElementById('hp' + rank);
    if (!hp) return;

    level = parseInt(level, 10);
    if (isNaN(level) || level < 0) level = 0;
    if (level > 2) level = 2;

    var years = parseInt(hp.getAttribute('data-years'), 10);
    var companyTotalCols = years > 1 ? 1 : 0;
    if (isNaN(years) || years < 1) years = 1;

    var periods = parseInt(hp.getAttribute('data-periods'), 10);
    if (isNaN(periods) || periods < 1) periods = years;

    var cols = document.querySelectorAll('td.' + p + ', th.' + p);
    cols.forEach(function(c) { c.style.display = 'none'; });

    var dataareaidTotals = document.querySelectorAll('td.pt' + rank);
    dataareaidTotals.forEach(function(c) { c.style.display = 'none'; });

    var companyTotals = document.querySelectorAll('td.ctp' + rank + ', th.ctp' + rank);
    companyTotals.forEach(function(c) { c.style.display = 'none'; });

    var yearHeaders = document.querySelectorAll('th.yhp' + rank);
    yearHeaders.forEach(function(c) { c.style.display = 'none'; });

    if (level === 0) {

        if (years > 1) {

            dataareaidTotals.forEach(function(c) {
                c.style.display = '';
            });

        } else {

            document.querySelectorAll(
                'td.ytp' + rank +
                ', th.ytp' + rank
            ).forEach(function(c) {
                c.style.display = '';
            });

            yearHeaders.forEach(function(c) {
                c.style.display = '';
            });

        }

        hp.setAttribute('colspan', 1);
    }

    if (level === 1) 
    {
        yearHeaders.forEach(function(c) { c.colSpan = 1; c.style.display = ''; });
        document.querySelectorAll('td.ytp' + rank + ', th.ytp' + rank).forEach(function(c) {
            c.style.display = '';
        });
        if (years > 1) {
            companyTotals.forEach(function(c) {
        c.style.display = '';
    });
}
        hp.setAttribute('colspan', years + companyTotalCols);
    }

    if (level === 2) {
        yearHeaders.forEach(function(c) {
            var full = parseInt(c.getAttribute('data-full'), 10);
            if (isNaN(full) || full < 1) full = 1;
            c.colSpan = full;
            c.style.display = '';
        });
        cols.forEach(function(c) { c.style.display = ''; });
        if (years > 1) {
            companyTotals.forEach(function(c) {
        c.style.display = '';
    });
}
        hp.setAttribute('colspan', periods + companyTotalCols);
    }

    hp.setAttribute('data-level', level);

    // -- Fondo azul en YTD y PTD solo en nivel 2 --
    var BG_TOTAL   = '#f4f6fb';
    var BORDER_TOP = '15px solid #f4f6fb';

    var totalCells = document.querySelectorAll(
        'tr.sh td.pt' + rank +
        ', tr.sh td.ctp' + rank +
        ', tr.sh td.ytp' + rank
    );
    totalCells.forEach(function(c) {
        c.style.background = level === 2 ? BG_TOTAL : '';
    });

    var firstTotalCells = document.querySelectorAll(
        'tr.sh.first td.pt' + rank +
        ', tr.sh.first td.ctp' + rank +
        ', tr.sh.first td.ytp' + rank
    );
    firstTotalCells.forEach(function(c) {
        if (level === 2) {
            c.style.setProperty('border-top', BORDER_TOP, 'important');
        } else {
            c.style.removeProperty('border-top');
        }
    });
}

function expandAlldataareaids() {
    var headers = Array.prototype.slice.call(
        document.querySelectorAll('th.ph')
    );
    var ranks = headers.map(function(h) {
        return h.id.replace('hp', '').trim();
    });
    ranks.forEach(function(rank) {
        var hp = document.getElementById('hp' + rank);
        var level = hp ? parseInt(hp.getAttribute('data-level'), 10) : 0;
        if (isNaN(level)) level = 0;
        setdataareaidState(rank, Math.min(level + 1, 2));
    });
}

function collapseAlldataareaids() {
    var headers = Array.prototype.slice.call(
        document.querySelectorAll('th.ph')
    );
    var ranks = headers.map(function(h) {
        return h.id.replace('hp', '').trim();
    });
    ranks.forEach(function(rank) {
        var hp = document.getElementById('hp' + rank);
        var level = hp ? parseInt(hp.getAttribute('data-level'), 10) : 0;
        if (isNaN(level)) level = 0;
        setdataareaidState(rank, Math.max(level - 1, 0));
    });
}


function showProviderTooltip(el, evt){

    var tooltip = document.getElementById('providerTooltip');

    if(!tooltip) return;

    var raw = el.getAttribute('data-tip');

    if(!raw || raw.trim() === '') return;

    var rows = raw.split('|');

    var html = '<div class=""tt-title"">Top 10 Proveedores / Clientes</div>';

rows.forEach(function(r){

    var p = r.split(':::');

    var name = p[0] || '';
    var val  = p[1] || '';
    var cls = val.indexOf('-') >= 0
    ? 'tt-val neg'
    : 'tt-val';

    html +=
        '<div class=""tt-row"">' +
            '<span class=""tt-name"">' + name + '</span>' +
            '<span class=""' + cls + '"">' + val + '</span>' +
        '</div>';
});

    tooltip.innerHTML = html;

    tooltip.style.display = 'block';

    var mouseX = evt.pageX;
    var mouseY = evt.pageY;

    var tooltipWidth  = tooltip.offsetWidth;
    var tooltipHeight = tooltip.offsetHeight;

    var windowWidth  = window.innerWidth;
    var windowHeight = window.innerHeight;

    var left = mouseX + 15;
    var top  = mouseY + 15;

    /* =====================================================
    SI SE SALE POR ABAJO → MOSTRAR HACIA ARRIBA
    ===================================================== */

    if(top + tooltipHeight > windowHeight){

        top = mouseY - tooltipHeight - 25;
    }

    /* =====================================================
    SI SE SALE POR DERECHA → MOSTRAR HACIA IZQUIERDA
    ===================================================== */

    if(left + tooltipWidth > windowWidth){

        left = mouseX - tooltipWidth - 25;
    }

    /* =====================================================
    APPLY
    ===================================================== */

    tooltip.style.left = left + 'px';
    tooltip.style.top  = top  + 'px';
}

function hideProviderTooltip(){

    var tooltip = document.getElementById('providerTooltip');

    if(tooltip){
        tooltip.style.display = 'none';
    }
}

</script>
"

