VAR _style = "
<style>

/* =========================================================
   RESET GENERAL
   =========================================================
   Aplica reglas base a TODOS los elementos:
   - box-sizing evita problemas de tamaños
   - margin/padding en 0 elimina espacios por defecto
========================================================= */
*{
    box-sizing:border-box;
    margin:0;
    padding:0;
}

/* =========================================================
   VARIABLES GLOBALES
   =========================================================
   Variables reutilizables para anchos principales
========================================================= */
:root{
    --pozo-width: 95px;        
    --total-width: 75px;  /* cuando se expande meses y YTD  */
}

/* =========================================================
   CONTENEDOR PRINCIPAL DEL VISUAL
   =========================================================
   .wrap:
   - contenedor padre completo
   - permite posicionar botones flotantes
   - padding-top crea espacio superior para toolbar
========================================================= */
.wrap{
    position:relative;
    width:100%;
    overflow:visible;
    padding-top:35px;
}

/* =========================================================
   CONTENEDOR SCROLLABLE DE LA TABLA
   =========================================================
   .tw:
   - SOLO la tabla hace scroll horizontal
   - toolbar permanece fijo fuera del scroll
========================================================= */
.tw{
    font-family:Segoe UI SemiBold, Arial, sans-serif;
    font-size:14px;
    width:100%;
    overflow-x:auto;
    overflow-y:auto;
    position:relative;
}

/* =========================================================
   TABLA BASE
   =========================================================
   border-spacing crea separación visual entre columnas
========================================================= */
table{
    border-collapse:separate;
    border-spacing:1.5px 0;
    background:rgba(0,0,0,0.08);
    table-layout:auto;
    width:max-content;
}

/* =========================================================
   HEADERS GENERALES
   =========================================================
   Estilo base para TODOS los th
========================================================= */
th{
    background:#111111;
    color:#FFF;
    padding:5px 8px;
    text-align:center;
    font-weight:600;
    font-size:13px;
    white-space:nowrap;
    border-bottom:1.5px solid #fff;
}

/* =========================================================
   PRIMERA COLUMNA (Class / Sub-Class)
   =========================================================
   Mantiene ancho fijo para evitar deformaciones
========================================================= */
.sticky-col{
    position:sticky;
    left:0;
}

/* Header sticky */
th.sticky-col{
    width:160px;
    min-width:160px;
    z-index:99999;
    background:#111111;
    box-shadow: 3px 0 6px rgba(0,0,0,0.18);
}

/* Body sticky */
td.sticky-col{
    width:160px;
    min-width:160px;
    z-index:9999;
}

/* Fondo dinámico */
tr.gh td.sticky-col{
    background:#CCCCCC;
}

tr.sh td.sticky-col{
    background:#FFF;
}

/* Hover */
tr.gh:hover td.sticky-col{
    background:#bebebe;
}

tr.sh:hover td.sticky-col{
    background:#ededed;
}
/* =========================================================
   HEADER DE AÑO
   =========================================================
   Segunda fila del header
========================================================= */
th.yh{
    background:#111111;
    font-size:12px;
    text-align:center !important;
    vertical-align:middle;
    padding:0 !important;
    width:var(--pozo-width);
    min-width:var(--pozo-width);
    height:34px;
}

/* =========================================================
   HEADER DE MESES
   =========================================================
   Tercera fila del header
========================================================= */
th.mh{
    background:#111111;
    font-size:12px;
    font-weight:400;
    text-align:center !important;
    padding:0 !important;
    height:34px;
}

/* =========================================================
   HEADER DE pozoS
   =========================================================
   Primera fila del header
========================================================= */
th.ph{
    background:#111111;
    font-size:13px;
    font-weight:700;
    letter-spacing:0.3px;
    padding:0 !important;
    width:var(--pozo-width);
    min-width:var(--pozo-width);
    height:34px;
}

/* Hover también en columna sticky */
tr.gh:hover td:first-child{
    background:#bebebe;
}

tr.sh:hover td:first-child{
    background:#ededed;
}

/* =========================================================
   COLUMNAS DE DATOS MENSUALES
   =========================================================
   Ancho fijo para mantener alineación
========================================================= */
th.mh,
td.data{
    width:80px !important;
    min-width:80px !important;
    max-width:80px !important;
}

/* =========================================================
   CELDAS GENERALES
   ========================================================= */
td{
    padding:4px 6px;
    text-align:center;
    vertical-align:middle;
    white-space:nowrap;
    height:28px;
    border-bottom:1px solid #E3E3E3;
}

/* =========================================================
   FILAS DE GRUPO
   =========================================================
   Revenue / DWP / Operational Result
========================================================= */
tr.gh td{
    background:#CCCCCC;
    color:#000;
    font-size:13.5px;
    font-weight:600;
    cursor:pointer;
}

/* Hover grupo */
tr.gh:hover td{
    background:#bebebe;
}

/* =========================================================
   FILAS HIJAS
   =========================================================
   Subclases
========================================================= */
tr.sh td{
    background:#FFF;
}

tr.sh td:first-child{
    padding-left:22px;

    color:#333;
    font-size:13px;
}

tr.sh:hover td{
    background:#ededed;
}

/* Separación visual */
tr.sh.first td{
    border-top:15px solid #fff;
}

tr.sh.first-global td{
    border-top:0px solid #fff;
}

tr.sh.last td{
    border-bottom:0px solid #fff;
}

tr.gh td:first-child{
    background:#CCCCCC;
}

tr.sh td:first-child{
    background:#FFF;
}

/* =========================================================
   VALORES NEGATIVOS
   ========================================================= */
.neg{
    color:#0073FF;
}

tr.gh .neg{
    color:#0073FF;
}

tr.sh .neg{
    color:#0073FF;
}

/* =========================================================
   ICONO EXPAND/COLLAPSE
   ========================================================= */
.tog{
    display:inline-flex;
    align-items:center;
    justify-content:center;
    width:14px;
    height:14px;
    margin-right:8px;
    border:0.5px solid #bbb;
    border-radius:1.5px;
    background:#b0b0b0;
    color:#000;
    font-size:13px;
}

/* Ajuste visual del símbolo + / - */
.tog .ico{
