}

/* =========================================================
   CONTENEDOR DE NOMBRE DE pozo
   ========================================================= */
.pw{
    display:flex;
    align-items:center;
    justify-content:center;
}

/* =========================================================
   COLUMNAS TOTAL
   ========================================================= */
th.total,
td.total{
