</style>"

-- ============================================================
-- ANIOS Y MESES GLOBALES (periodos con datos en el contexto)
-- ============================================================
VAR _aniosBase =
    ADDCOLUMNS(
        FILTER(
            VALUES( calendariocontable[año] ),
            NOT ISBLANK( calendariocontable[año] )
            && CALCULATE( COUNTROWS( 'origenesdecontabilidad-PL' ) ) > 0
        ),
        "ord_y", calendariocontable[año]
    )
VAR _NumYears =
    COUNTROWS(_aniosBase)

VAR _periodosBase =
    ADDCOLUMNS(
        FILTER(
            SUMMARIZE(
                calendariocontable,
                calendariocontable[año],
                calendariocontable[month_en]
            ),
            NOT ISBLANK( calendariocontable[año] )
            && NOT ISBLANK( calendariocontable[month_en] )
            && CALCULATE( COUNTROWS( 'origenesdecontabilidad-PL' ) ) > 0
        ),
        "ord_y", calendariocontable[año],
        "ord_m",
            SWITCH( TRUE(),
                calendariocontable[month_en]="Jan",1, calendariocontable[month_en]="Feb",2,
                calendariocontable[month_en]="Mar",3, calendariocontable[month_en]="Apr",4,
                calendariocontable[month_en]="May",5, calendariocontable[month_en]="Jun",6,
                calendariocontable[month_en]="Jul",7, calendariocontable[month_en]="Aug",8,
                calendariocontable[month_en]="Sep",9, calendariocontable[month_en]="Oct",10,
                calendariocontable[month_en]="Nov",11,calendariocontable[month_en]="Dec",12
            )
    )

-- ============================================================
-- pozoS ordenados por valor absoluto DESC
-- ============================================================
VAR _enableProviderTooltip = TRUE() //Habilitar o deshabilitar tooltip
VAR _enablepozoThreshold = TRUE() -- Se activa o no el valor mínimo
VAR _pozoThreshold = 'Min - USD'[Valor de Min - USD] --VALOR minimo del total de Operationaal Result
VAR _pozos =
    ADDCOLUMNS(
        FILTER(
            FILTER(
                VALUES( 'origenesdecontabilidad-PL'[pozo] ),
                NOT ISBLANK( 'origenesdecontabilidad-PL'[pozo] )
            ),
            VAR _totalpozo =
            CALCULATE(

                SUM( 'origenesdecontabilidad-PL'[amrusd] ),

                'origenesdecontabilidad-PL'[ClassCG] IN {
                    "Revenue",
                    "DWP",
                    "Operational Result"
                }
            )
            RETURN
            NOT ISBLANK( _totalpozo ) && _totalpozo <> 0
            && IF(
                _enablepozoThreshold,
                ABS(_totalpozo) >= _pozoThreshold,
                TRUE()
            )
        ),
        "ord_p",
            ABS(
                CALCULATE(
                    SUM( 'origenesdecontabilidad-PL'[amrusd] )
                )
            )
    )
 VAR _Numpozos =
    COUNTROWS(_pozos)
-- ============================================================
-- ANIOS Y MESES POR pozo (solo periodos con datos para ese pozo)
-- ============================================================
VAR _pozoAnio =
    FILTER(
        GENERATE(
            _pozos,
            VAR _p_inner = 'origenesdecontabilidad-PL'[pozo]
            RETURN
                ADDCOLUMNS(
                    _aniosBase,
                    "tiene_dato",
                        CALCULATE(
                            SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                            'origenesdecontabilidad-PL'[pozo] = _p_inner
                        )
                )
        ),
        NOT ISBLANK( [tiene_dato] ) && [tiene_dato] <> 0
    )

VAR _pozoPeriodo =
    FILTER(
        GENERATE(
            _pozos,
            VAR _p_inner = 'origenesdecontabilidad-PL'[pozo]
            RETURN
                ADDCOLUMNS(
                    _periodosBase,
                    "tiene_dato",
                        CALCULATE(
                            SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                            'origenesdecontabilidad-PL'[pozo] = _p_inner
                        )
                )
        ),
        NOT ISBLANK( [tiene_dato] ) && [tiene_dato] <> 0
    )

-- ============================================================
-- ENCABEZADO FILA 1: nombres de pozo con colspan
-- ============================================================
VAR _thpozos =
    CONCATENATEX(
        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[pozo]
        VAR _aniospozo =
            FILTER( _pozoAnio, 'origenesdecontabilidad-PL'[pozo] = _p )
        VAR _numY =
            COUNTROWS( _aniospozo )
        VAR _numPeriodos =
            SUMX(
                _aniospozo,
                VAR _y = calendariocontable[año]
                VAR _cntMes =
                    COUNTROWS(
                        FILTER(
                            _pozoPeriodo,
                            'origenesdecontabilidad-PL'[pozo] = _p
                            && calendariocontable[año] = _y
                        )
                    )
                RETURN _cntMes + 1
            )
        VAR _rankpozo =
        RANKX( _pozos, [ord_p], , DESC, DENSE )

        RETURN
        "<th
            id='hp" & _rankpozo & "'
            data-level='0'
            data-years='" & IF( ISBLANK(_numY), 0, _numY ) & "'
            data-periods='" & IF( ISBLANK(_numPeriodos), 0, _numPeriodos ) & "'
            colspan='1'
            class='ph" & "" & "'>

            <div class='pw'>
                " & _p & "
            </div>

        </th>",
        "", [ord_p], DESC
    )

-- ============================================================
-- ENCABEZADO FILA 2: año repetido por pozo
-- ============================================================
VAR _thAnios =
    CONCATENATEX(
        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[pozo]
        VAR _aniospozo =
            FILTER( _pozoAnio, 'origenesdecontabilidad-PL'[pozo] = _p )
        VAR _rankpozo =
        RANKX( _pozos, [ord_p], , DESC, DENSE )
        RETURN
            CONCATENATEX(
                _aniospozo,
                VAR _y = calendariocontable[año]
                VAR _rankAnio = RANKX( _aniospozo, [ord_y], , ASC, DENSE )
                VAR _numM =
                    COUNTROWS(
                        FILTER(
                            _pozoPeriodo,
                            'origenesdecontabilidad-PL'[pozo] = _p
                            && calendariocontable[año] = _y
                        )
                    )
                RETURN
                    "<th
                        id='hy" & _rankpozo & "_" & _rankAnio & "'
                        data-full='" & (_numM + 1) & "'
                        colspan='1'
                        class='yh yhp" & _rankpozo & "'
                        style='display:none;'>" &
                    _y &

                    "</th>",
                "", [ord_y], ASC
            ) &
            IF(
                _NumYears > 1,

                "<th
                    rowspan='2'
                    style='display:none;'
                    class='yh company-total p" & _rankpozo & " ctp" & _rankpozo & "'>
                    PTD
                </th>",

                ""
            ),
        "", [ord_p], DESC
    )

-- ============================================================
-- ENCABEZADO FILA 3: meses y YTD de cada anio por pozo
-- ============================================================
VAR _thMeses =
    CONCATENATEX(
        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[pozo]
        VAR _aniospozo =
            FILTER( _pozoAnio, 'origenesdecontabilidad-PL'[pozo] = _p )
        VAR _rankpozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
        RETURN
            CONCATENATEX(
                _aniospozo,
                VAR _y = calendariocontable[año]
                VAR _rankAnio = RANKX( _aniospozo, [ord_y], , ASC, DENSE )
                VAR _mesespozoAnio =
                    FILTER(
                        _pozoPeriodo,
                        'origenesdecontabilidad-PL'[pozo] = _p
                        && calendariocontable[año] = _y
                    )
                VAR _thM =
                    CONCATENATEX(
                        _mesespozoAnio,
                        VAR _m = calendariocontable[month_en]
                        RETURN
                            "<th style='display:none;' class='mh month p" & _rankpozo & " py" & _rankpozo & "_" & _rankAnio & "'>" & _m & "</th>",
                        "", [ord_m], ASC
                    )
            RETURN
                _thM &
                "<th
                    style='display:none;'
                    class='mh total year-total p" & _rankpozo &
                    " ytp" & _rankpozo &
                    " py" & _rankpozo & "_" & _rankAnio &
                    "'>YTD</th>",
                "", [ord_y], ASC
            ),
        "", [ord_p], DESC
    ) 
VAR _thead =
    "<thead>
       <tr>
            <th class='sticky-col'
                rowspan='3'
                style='vertical-align:middle;text-align:left;padding-left:10px;'>
                Class / Sub-Class
            </th>"
            & _thpozos &
            IF(
                _Numpozos > 1,

                "<th rowspan='3' class='grandtotal'>
                    PTD
                </th>",

                ""
            ) &
        "</tr>
        <tr>" &
            _thAnios &
        "</tr>
        <tr>" &
            _thMeses &
        "</tr>

    </thead>"

-- ============================================================
-- ORDEN DE CLASES
-- ============================================================
VAR _ordenClass = DATATABLE(
    "grp", STRING, "ord", INTEGER,
    {{"Revenue",1},{"DWP",2},{"Operational Result",3},{"Sin Clasificar",4}}
)
-- ============================================================
-- CLASES GLOBALES
-- ============================================================
// VAR _grupos =
//     ADDCOLUMNS(
//         FILTER(
//             VALUES( 'origenesdecontabilidad-PL'[ClassCG] ),
//             NOT ISBLANK( 'origenesdecontabilidad-PL'[ClassCG] )
//         ),
//         "ord_g",
//             MAXX( FILTER( _ordenClass, [grp] = 'origenesdecontabilidad-PL'[ClassCG] ), [ord] )
//     )

    VAR _grupos =
    FILTER(
        ADDCOLUMNS(
            FILTER( VALUES( 'origenesdecontabilidad-PL'[ClassCG] ), 
            NOT ISBLANK( 'origenesdecontabilidad-PL'[ClassCG] ) 
             && 'origenesdecontabilidad-PL'[ClassCG] <> "Sin Clasificar"
            ),"ord_g", MAXX( FILTER( _ordenClass, [grp] = 'origenesdecontabilidad-PL'[ClassCG] ), [ord] )
        ),
        NOT ISBLANK( [ord_g] )
    )

-- ============================================================
-- CONSTRUCCIÓN DE FILAS
-- ============================================================
VAR _filas =
    CONCATENATEX(
        _grupos,
        VAR _g   = 'origenesdecontabilidad-PL'[ClassCG]
        VAR _gid = SUBSTITUTE( SUBSTITUTE( SUBSTITUTE( _g, " ", "_" ), "/", "_" ), "&", "_" )
        VAR _grandTotal =
            SWITCH(
                TRUE(),

                _g = "Revenue",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] = "Revenue"
                    ),

                _g = "DWP",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP"}
                    ),

                _g = "Operational Result",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] IN {
                            "Revenue",
                            "DWP",
                            "Operational Result"
                        }
                    )
            )

        VAR _grandFmt =
            IF(
                ISBLANK(_grandTotal),
                "",
                IF(
                    _grandTotal < 0,
                    "-" & FORMAT( ROUND( ABS(_grandTotal)/1000, 0 ), "#,##0" ),
                    FORMAT( ROUND( _grandTotal/1000, 0 ), "#,##0" )
                )
            )

        VAR _grandCls =
            IF( NOT ISBLANK(_grandTotal) && _grandTotal < 0, " neg", "" )

        -- Celdas del grupo: total del pozo, luego anios y meses al expandir
        VAR _celdasGrupo =
            CONCATENATEX(
                _pozos,
                VAR _p = 'origenesdecontabilidad-PL'[pozo]
                VAR _aniospozo = FILTER( _pozoAnio, 'origenesdecontabilidad-PL'[pozo] = _p )
                VAR _rankpozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
                VAR _tdsPeriodos =
                    CONCATENATEX(
                        _aniospozo,
                        VAR _y = calendariocontable[año]
                        VAR _rankAnio = RANKX( _aniospozo, [ord_y], , ASC, DENSE )
                        VAR _mesespozoAnio =
                            FILTER(
                                _pozoPeriodo,
                                'origenesdecontabilidad-PL'[pozo] = _p
                                && calendariocontable[año] = _y
                            )
                        VAR _tdsMeses =
                            CONCATENATEX(
                                _mesespozoAnio,
                                VAR _m = calendariocontable[month_en]
                                VAR _revenue =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[pozo] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                                        calendariocontable[año] = _y,
                                        calendariocontable[month_en] = _m
                                    )

                                VAR _dwp =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[pozo] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                                        calendariocontable[año] = _y,
                                        calendariocontable[month_en] = _m
                                    )

                                VAR _op =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[pozo] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = "Operational Result",
                                        calendariocontable[año] = _y,
                                        calendariocontable[month_en] = _m
                                    )

                                VAR _v =
                                    SWITCH(
                                        TRUE(),
                                        _g = "Revenue",
                                            _revenue,
                                        _g = "DWP",
                                            _revenue + _dwp,
                                        _g = "Operational Result",
                                            _revenue + _dwp + _op,
                                        BLANK()
                                    )
                                VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                                VAR _fmt =
                                    IF( ISBLANK(_v), "",
                                        IF( _v < 0,
                                            "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                                            FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                                        )
                                    )
                                RETURN
                                    "<td style='display:none;' class='data month p" & _rankpozo & " py" & _rankpozo & "_" & _rankAnio & _cls & "'>" & _fmt & "</td>",
                                "", [ord_m], ASC
                            )

                        VAR _revYear =
