                                VAR _fmtYear =
                                    IF( ISBLANK(_yearTotal), "",
                                        IF( _yearTotal < 0,
                                            "-" & FORMAT( ROUND( ABS(_yearTotal)/1000, 0 ), "#,##0" ),
                                            FORMAT( ROUND( _yearTotal/1000, 0 ), "#,##0" )
                                        )
