                                    "<td style='display:none;' class='total year-total p" & _rankpozo & " ytp" & _rankpozo & " py" & _rankpozo & "_" & _rankAnio & _clsYear & "'>" &
                                        _fmtYear &
                                    "</td>",
                                "", [ord_y], ASC
                            )

                        VAR _totalpozo =
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[pozo] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                                    )
                        VAR _fmtTotal =
                            IF( ISBLANK(_totalpozo), "",
                                IF( _totalpozo < 0,
