                            )
                    RETURN

                        _tdsPeriodos &
                        IF(
                            _NumYears > 1,

                            "<td
                                style='display:none;'
                                class='total company-total p" & _rankpozo &
                                " ctp" & _rankpozo &
                                _clsTotal &
                                "'>" &
                                _fmtTotal &
                            "</td>",

                            ""
                        ) &

                        "<td
                            class='total pozo-total pt" & _rankpozo &
                            _clsTotal &
                            "'>" &
                            _fmtTotal &
                        "</td>",
                        "", [ord_p], DESC
                    )

                VAR _esPrimerGrupo = [ord_g] = 1

                VAR _extraH =
                    IF( _esPrimerGrupo && _indexH = 1, " first-global", "" ) &
                    IF( _indexH = 1, " first", "" ) &
                    IF( _indexH = _countHijos, " last", "" )

                VAR _grandSub =
                    CALCULATE(
