"
<script>

function setpozoState(rank, level) {
    var p = 'p' + rank;
    var hp = document.getElementById('hp' + rank);
    if (!hp) return;

    level = parseInt(level, 10);
    if (isNaN(level) || level < 0) level = 0;
    if (level > 2) level = 2;

    var years = parseInt(hp.getAttribute('data-years'), 10);
    var companyTotalCols = document.querySelector('th.ctp' + rank) ? 1 : 0;
    if (isNaN(years) || years < 1) years = 1;

    var periods = parseInt(hp.getAttribute('data-periods'), 10);
    if (isNaN(periods) || periods < 1) periods = years;

    var cols = document.querySelectorAll('td.' + p + ', th.' + p);
    cols.forEach(function(c) { c.style.display = 'none'; });

    var pozoTotals = document.querySelectorAll('td.pt' + rank);
    pozoTotals.forEach(function(c) { c.style.display = 'none'; });

    var companyTotals = document.querySelectorAll('td.ctp' + rank + ', th.ctp' + rank);
    companyTotals.forEach(function(c) { c.style.display = 'none'; });

    var yearHeaders = document.querySelectorAll('th.yhp' + rank);
    yearHeaders.forEach(function(c) {
        c.colSpan = 1;
        c.style.display = 'none';
    });

    if (level === 0) {

        pozoTotals.forEach(function(c) {
            c.style.display = '';
        });
        hp.setAttribute('colspan', 1);
    }

    if (level === 1) 
    {
        yearHeaders.forEach(function(c) { c.colSpan = 1; c.style.display = ''; });
        document.querySelectorAll('td.ytp' + rank + ', th.ytp' + rank).forEach(function(c) {
            c.style.display = '';
        });
        if (companyTotalCols > 0) {
            companyTotals.forEach(function(c) {
        c.style.display = '';
    });
}
        hp.setAttribute('colspan', years + companyTotalCols);
    }

    if (level === 2) {
        yearHeaders.forEach(function(c) {
            var full = parseInt(c.getAttribute('data-full'), 10);
            if (isNaN(full) || full < 1) full = 1;
            c.colSpan = full;
            c.style.display = '';
        });
        cols.forEach(function(c) { c.style.display = ''; });
        if (companyTotalCols > 0) {
            companyTotals.forEach(function(c) {
        c.style.display = '';
    });
}
        hp.setAttribute('colspan', periods + companyTotalCols);
    }

    hp.setAttribute('data-level', level);

    // -- Fondo azul en YTD y PTD solo en nivel 2 --
    var BG_TOTAL   = '#f4f6fb';
    var BORDER_TOP = '15px solid #f4f6fb';

    var totalCells = document.querySelectorAll(
        'tr.sh td.pt' + rank +
        ', tr.sh td.ctp' + rank +
        ', tr.sh td.ytp' + rank
    );
    totalCells.forEach(function(c) {
        c.style.background = level === 2 ? BG_TOTAL : '';
    });

    var firstTotalCells = document.querySelectorAll(
        'tr.sh.first td.pt' + rank +
        ', tr.sh.first td.ctp' + rank +
        ', tr.sh.first td.ytp' + rank
    );
    firstTotalCells.forEach(function(c) {
        if (level === 2) {
            c.style.setProperty('border-top', BORDER_TOP, 'important');
        } else {
            c.style.removeProperty('border-top');
        }
    });
}

function getpozoRanks() {
    var headers = Array.prototype.slice.call(
        document.querySelectorAll('th.ph')
    );
    return headers.map(function(h) {
        return h.id.replace('hp', '').trim();
    });
}

function getpozoGlobalLevel(ranks) {
    var maxLevel = 0;
    ranks.forEach(function(rank) {
        var hp = document.getElementById('hp' + rank);
        var level = hp ? parseInt(hp.getAttribute('data-level'), 10) : 0;
        if (isNaN(level)) level = 0;
        if (level > maxLevel) maxLevel = level;
    });
    return maxLevel;
}

function expandAllpozos() {
    var ranks = getpozoRanks();
    var targetLevel = Math.min(getpozoGlobalLevel(ranks) + 1, 2);
    ranks.forEach(function(rank) {
        setpozoState(rank, targetLevel);
    });
}

function collapseAllpozos() {
    var ranks = getpozoRanks();
    var targetLevel = Math.max(getpozoGlobalLevel(ranks) - 1, 0);
    ranks.forEach(function(rank) {
        setpozoState(rank, targetLevel);
    });
}


function showProviderTooltip(el, evt){

    var tooltip = document.getElementById('providerTooltip');

    if(!tooltip) return;

    var raw = el.getAttribute('data-tip');

    if(!raw || raw.trim() === '') return;

    var rows = raw.split('|');

    var html = '<div class=""tt-title"">Top 10 Proveedores / Clientes</div>';

rows.forEach(function(r){

    var p = r.split(':::');

    var name = p[0] || '';
    var val  = p[1] || '';
    var cls = val.indexOf('-') >= 0
    ? 'tt-val neg'
    : 'tt-val';

    html +=
        '<div class=""tt-row"">' +
            '<span class=""tt-name"">' + name + '</span>' +
            '<span class=""' + cls + '"">' + val + '</span>' +
        '</div>';
});

    tooltip.innerHTML = html;

    tooltip.style.display = 'block';

    var mouseX = evt.pageX;
    var mouseY = evt.pageY;

    var tooltipWidth  = tooltip.offsetWidth;
    var tooltipHeight = tooltip.offsetHeight;

    var windowWidth  = window.innerWidth;
    var windowHeight = window.innerHeight;

    var left = mouseX + 15;
    var top  = mouseY + 15;

    /* =====================================================
    SI SE SALE POR ABAJO → MOSTRAR HACIA ARRIBA
    ===================================================== */

    if(top + tooltipHeight > windowHeight){

        top = mouseY - tooltipHeight - 25;
    }

    /* =====================================================
    SI SE SALE POR DERECHA → MOSTRAR HACIA IZQUIERDA
    ===================================================== */

    if(left + tooltipWidth > windowWidth){

        left = mouseX - tooltipWidth - 25;
    }

    /* =====================================================
    APPLY
    ===================================================== */

    tooltip.style.left = left + 'px';
    tooltip.style.top  = top  + 'px';
}

function hideProviderTooltip(){

    var tooltip = document.getElementById('providerTooltip');

    if(tooltip){
        tooltip.style.display = 'none';
    }
}

</script>
