</style>"

-- ============================================================
-- FLAGS DE CONTROL
-- ============================================================
VAR _enableProviderTooltip = FALSE()
VAR _enableRevenueVisible  = TRUE()
VAR _enablepozoThreshold   = TRUE()
VAR _pozoThreshold         = 'Min - USD'[Valor de Min - USD]

VAR _pctFormat = "0%" --Formato del porcentaje. Entero
// VAR _pctFormat = "0.00%" --Formato del porcentaje. 1 decimal

-- ============================================================
-- ETAPAS
-- ============================================================
VAR _etapasBase =
    ADDCOLUMNS(
        FILTER(
            SUMMARIZE(
                dimensionesfinancieras,
                dimensionesfinancieras[etapaestandar],
                dimensionesfinancieras[etapasorden]
            ),
            NOT ISBLANK( dimensionesfinancieras[etapaestandar] )
            && CALCULATE( COUNTROWS( 'origenesdecontabilidad-PL' ) ) > 0
        ),
        "ord_e", dimensionesfinancieras[etapasorden]
    )

VAR _NumEtapas = COUNTROWS( _etapasBase )

-- ============================================================
-- POZOS
-- ============================================================
VAR _pozos =
    ADDCOLUMNS(
        FILTER(
            FILTER(
                VALUES( 'origenesdecontabilidad-PL'[pozo] ),
                NOT ISBLANK( 'origenesdecontabilidad-PL'[pozo] )
            ),
            VAR _totalpozo =
                CALCULATE(
                    SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                    'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                )
            RETURN
                NOT ISBLANK( _totalpozo ) && _totalpozo <> 0
                && IF(
                    _enablepozoThreshold,
                    ABS( _totalpozo ) >= _pozoThreshold,
                    TRUE()
                )
        ),
        "ord_p",
            ABS(
                CALCULATE(
                    SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                    'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                )
            )
    )

VAR _Numpozos = COUNTROWS( _pozos )

-- ============================================================
-- ETAPAS POR POZO
-- ============================================================
VAR _pozoEtapa =
    FILTER(
        GENERATE(
            _pozos,
            VAR _p_inner = 'origenesdecontabilidad-PL'[pozo]
            RETURN
                ADDCOLUMNS(
                    _etapasBase,
                    "tiene_dato",
                        CALCULATE(
                            SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                            'origenesdecontabilidad-PL'[pozo]    = _p_inner,
                            'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP","Operational Result"}
                        )
                )
        ),
        NOT ISBLANK( [tiene_dato] ) && [tiene_dato] <> 0
        && ABS([tiene_dato]) >= 1000
    )

-- ============================================================
-- TOTALES GLOBALES
-- ============================================================
VAR _revenueTotal =
    CALCULATE(
        SUM('origenesdecontabilidad-PL'[amrusd]),
        KEEPFILTERS( 'origenesdecontabilidad-PL'[ClassCG] = "Revenue" )
    )

VAR _hasRevenue =
    NOT ISBLANK(_revenueTotal) && _revenueTotal <> 0

VAR _hasOperationalResult =
    CALCULATE(
        COUNTROWS('origenesdecontabilidad-PL'),
        'origenesdecontabilidad-PL'[ClassCG] = "Operational Result"
    ) > 0

VAR _dwpTotal =
    CALCULATE(
        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
        'origenesdecontabilidad-PL'[ClassCG] = "DWP"
    )

-- ============================================================
-- TOTAL OPERATIONAL RESULT GLOBAL (Rev + DWP + OR)
-- Lo calculamos aquí arriba para reutilizarlo en % de subclases OR
-- ============================================================
VAR _orTotalGlobal =
    CALCULATE(
        SUM('origenesdecontabilidad-PL'[amrusd]),
        'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP","Operational Result"}
    )

-- ============================================================
-- ENCABEZADO FILA 1
-- ============================================================
VAR _thpozos =
    CONCATENATEX(
        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[pozo]
        VAR _etapaspozo = FILTER( _pozoEtapa, 'origenesdecontabilidad-PL'[pozo] = _p )
        VAR _numE = COUNTROWS( _etapaspozo )
        VAR _rankpozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
        VAR _dataEtapas = IF( ISBLANK(_numE), 0, _numE )
        RETURN
            "<th
                id='hp" & _rankpozo & "'
                data-level='0'
                data-etapas='" & _dataEtapas & "'
                colspan='2'
                class='ph'>
                <div class='pw'>" & _p & "</div>
            </th>",
        "", [ord_p], DESC
    )

-- ============================================================
-- ENCABEZADO FILA 2
-- ============================================================
VAR _thEtapas =
    CONCATENATEX(
        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[pozo]
        VAR _etapaspozo = FILTER( _pozoEtapa, 'origenesdecontabilidad-PL'[pozo] = _p )
        VAR _rankpozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
        VAR _thEtapasCols =
            CONCATENATEX(
                _etapaspozo,
                VAR _e = dimensionesfinancieras[etapaestandar]
                VAR _rankEtapa = RANKX( _etapaspozo, [ord_e], , ASC, DENSE )
                RETURN
                    "<th
                        style='display:none;'
                        class='eh etapa p" & _rankpozo &
                        " ep" & _rankpozo & "_" & _rankEtapa & "'>" &
                        _e &
                    "</th>",
                "", [ord_e], ASC
            )
        RETURN
            "<th class='eh pct-h pp" & _rankpozo & "'><div class='pct-header'>%</div></th>" &
            _thEtapasCols &
            "<th class='eh total ptp" & _rankpozo & "'>PTD</th>",
        "", [ord_p], DESC
    )

VAR _thead =
    "<thead>
        <tr>
            <th class='sticky-col'
                rowspan='2'
                style='vertical-align:middle;text-align:left;padding-left:10px;'>
                Costo Directo
            </th>" &
            _thpozos &
            IF(
                _Numpozos > 1,
                    "<th rowspan='2' class='grandtotal pct-h'>%</th>" &
                    "<th rowspan='2' class='grandtotal'>Total</th>",
                ""
            ) &
        "</tr>
        <tr>" &
            _thEtapas &
        "</tr>
    </thead>"

-- ============================================================
-- ORDEN DE CLASES
-- ============================================================
VAR _ordenClass = DATATABLE(
    "grp", STRING, "ord", INTEGER,
    {{"Revenue",1},{"DWP",2},{"Operational Result",3}}
)

VAR _grupos =
    FILTER(
        ADDCOLUMNS(
            FILTER(
                VALUES( 'origenesdecontabilidad-PL'[ClassCG] ),
                NOT ISBLANK( 'origenesdecontabilidad-PL'[ClassCG] )
                && 'origenesdecontabilidad-PL'[ClassCG] IN { "Revenue", "DWP", "Operational Result" }
            ),
            "ord_g",
                MAXX(
                    FILTER( _ordenClass, [grp] = 'origenesdecontabilidad-PL'[ClassCG] ),
                    [ord]
                )
        ),
        NOT ISBLANK( [ord_g] )
    )

-- ============================================================
-- CONSTRUCCIÓN DE FILAS
-- ============================================================

VAR _revenueTotalGlobal =
    CALCULATE(
        SUM('origenesdecontabilidad-PL'[amrusd]),
        'origenesdecontabilidad-PL'[ClassCG] = "Revenue"
    )

VAR _filas =
    CONCATENATEX(
        _grupos,
        VAR _g   = 'origenesdecontabilidad-PL'[ClassCG]
        VAR _gid = SUBSTITUTE( SUBSTITUTE( SUBSTITUTE( _g, " ", "_" ), "/", "_" ), "&", "_" )

        -- Total del grupo según su lógica acumulativa
        VAR _grandTotal =
            IF(
                _g = "DWP",
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    'origenesdecontabilidad-PL'[ClassCG] IN { "Revenue", "DWP" }
                ),
                IF(
                    _g = "Operational Result",
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] IN { "Revenue", "DWP", "Operational Result" }
                    ),
                    -- Revenue: solo su propio valor
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] = _g
                    )
                )
            )

        VAR _grandFmt =
            IF( ISBLANK(_grandTotal), "",
                IF( _grandTotal < 0,
                    "-" & FORMAT( ROUND( ABS(_grandTotal)/1000, 0 ), "#,##0" ),
                    FORMAT( ROUND( _grandTotal/1000, 0 ), "#,##0" )
                )
            )

        VAR _grandCls = IF( NOT ISBLANK(_grandTotal) && _grandTotal < 0, " neg", "" )

        VAR _celdasGrupo =
            CONCATENATEX(
                _pozos,
                VAR _p = 'origenesdecontabilidad-PL'[pozo]
                VAR _rankpozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
                VAR _etapaspozo = FILTER( _pozoEtapa, 'origenesdecontabilidad-PL'[pozo] = _p )

                VAR _totalpozo =
                    IF(
                        _g = "DWP",
                        CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[pozo] = _p,
                            'origenesdecontabilidad-PL'[ClassCG] IN { "Revenue", "DWP" }
                        ),
                        IF(
                            _g = "Operational Result",
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[pozo] = _p,
                                'origenesdecontabilidad-PL'[ClassCG] IN { "Revenue", "DWP", "Operational Result" }
                            ),
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[pozo] = _p,
                                'origenesdecontabilidad-PL'[ClassCG] = _g
                            )
                        )
                    )

                VAR _fmtTotal =
                    IF( ISBLANK(_totalpozo), "",
                        IF( _totalpozo < 0,
                            "-" & FORMAT( ROUND( ABS(_totalpozo)/1000, 0 ), "#,##0" ),
                            FORMAT( ROUND( _totalpozo/1000, 0 ), "#,##0" )
                        )
                    )
                VAR _clsTotal = IF( ISBLANK(_totalpozo), "", IF( _totalpozo < 0, " neg", "" ) )

                VAR _tdsEtapas =
                    CONCATENATEX(
                        _etapaspozo,
                        VAR _e = dimensionesfinancieras[etapaestandar]
                        VAR _rankEtapa = RANKX( _etapaspozo, [ord_e], , ASC, DENSE )
                        VAR _v =
                            IF(
                                _g = "DWP",
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    'origenesdecontabilidad-PL'[pozo] = _p,
                                    'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP"},
                                    dimensionesfinancieras[etapaestandar] = _e
                                ),
                                IF(
                                    _g = "Operational Result",
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[pozo] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP","Operational Result"},
                                        dimensionesfinancieras[etapaestandar] = _e
                                    ),
                                    CALCULATE(
                                        SUM('origenesdecontabilidad-PL'[amrusd]),
                                        'origenesdecontabilidad-PL'[pozo] = _p,
                                        'origenesdecontabilidad-PL'[ClassCG] = _g,
                                        dimensionesfinancieras[etapaestandar] = _e
                                    )
                                )
                            )
                        VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                        VAR _fmt =
                            IF( ISBLANK(_v), "",
                                IF( _v < 0,
                                    "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                                    FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                                )
                            )
                        RETURN
                            "<td style='display:none;' class='data etapa-total p" & _rankpozo &
                            " ep" & _rankpozo & "_" & _rankEtapa & _cls & "'>" & _fmt & "</td>",
                        "", [ord_e], ASC
                    )
                VAR _revPozoGrupo =
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        REMOVEFILTERS('origenesdecontabilidad-PL'[SubClassCG]),
                        'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
                        'origenesdecontabilidad-PL'[pozo] = _p
                    )

                -- Total OR acumulado por pozo (para el denominador sin Rev)
                VAR _orAcumPozo =
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP","Operational Result"},
                        'origenesdecontabilidad-PL'[pozo] = _p
                    )

            VAR _numeradorGrupoPozo =
                IF(
                    _g = "DWP",
                    IF(
                        _hasRevenue,
                        -CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                            'origenesdecontabilidad-PL'[pozo] = _p
                        ),
                        ABS(
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                                'origenesdecontabilidad-PL'[pozo] = _p
                            )
                        )
                    ),
                    IF(
                        _g = "Operational Result",
                        IF(
                            _hasRevenue,
                            -CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] IN {
                                    "DWP",
                                    "Operational Result"
                                },
                                'origenesdecontabilidad-PL'[pozo] = _p
                            ),
                            ABS(
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    'origenesdecontabilidad-PL'[ClassCG] IN {
                                        "DWP",
                                        "Operational Result"
                                    },
                                    'origenesdecontabilidad-PL'[pozo] = _p
                                )
                            )
                        ),
                        0
                    )
                )

                VAR _totalCostoPozoGrupo =
                    IF(
                        _hasOperationalResult,
                        ABS(
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                REMOVEFILTERS(
                                    'origenesdecontabilidad-PL'[ClassCG],
                                    'origenesdecontabilidad-PL'[SubClassCG]
                                ),
                                'origenesdecontabilidad-PL'[ClassCG] IN {
                                    "DWP",
                                    "Operational Result"
                                },
                                'origenesdecontabilidad-PL'[pozo] = _p
                            )
                        ),
                        ABS(
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                REMOVEFILTERS(
                                    'origenesdecontabilidad-PL'[ClassCG],
                                    'origenesdecontabilidad-PL'[SubClassCG]
                                ),
                                'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                                'origenesdecontabilidad-PL'[pozo] = _p
                            )
                        )
                    )

                VAR _pctGrupoPozo =
                    IF(
                        _g = "Revenue",
                        "",
                        IF(
                            _hasRevenue,
                            IF(
                                NOT ISBLANK(_revPozoGrupo) && _revPozoGrupo <> 0,
                                FORMAT(
                                    DIVIDE(
                                        _numeradorGrupoPozo,
                                        ABS(_revPozoGrupo)
                                    ),
                                    _pctFormat
                                ),
                                ""
                            ),
                            IF(
                                NOT ISBLANK(_totalCostoPozoGrupo) && _totalCostoPozoGrupo <> 0,
                                FORMAT(
                                    DIVIDE(
                                        _numeradorGrupoPozo,
                                        _totalCostoPozoGrupo
                                    ),
                                    _pctFormat
                                ),
                                ""
                            )
                        )
                    )
            RETURN
                "<td class='pct-d pp" & _rankpozo & "'>" & _pctGrupoPozo & "</td>" &
                _tdsEtapas &
                "<td class='total pozo-total ptp" & _rankpozo & _clsTotal & "'>" & _fmtTotal & "</td>",
                "", [ord_p], DESC
            )

            VAR _numeradorGrandGrupo =
                IF(
                    _g = "DWP",
                    IF(
                        _hasRevenue,
                        -CALCULATE(
                            SUM('origenesdecontabilidad-PL'[amrusd]),
                            'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                        ),
                        ABS(
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                            )
                        )
                    ),
                    IF(
                        _g = "Operational Result",
                        IF(
                            _hasRevenue,
                            -CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[ClassCG] IN {
                                    "DWP",
                                    "Operational Result"
                                }
                            ),
                            ABS(
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    'origenesdecontabilidad-PL'[ClassCG] IN {
                                        "DWP",
                                        "Operational Result"
                                    }
                                )
                            )
                        ),
                        0
                    )
                )

        VAR _totalCostoGlobalGrupo =
            IF(
                _hasOperationalResult,
                ABS(
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        REMOVEFILTERS(
                            'origenesdecontabilidad-PL'[ClassCG],
                            'origenesdecontabilidad-PL'[SubClassCG]
                        ),
                        'origenesdecontabilidad-PL'[ClassCG] IN {
                            "DWP",
                            "Operational Result"
                        }
                    )
                ),
                ABS(
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        REMOVEFILTERS(
                            'origenesdecontabilidad-PL'[ClassCG],
                            'origenesdecontabilidad-PL'[SubClassCG]
                        ),
                        'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                    )
                )
            )

        VAR _pctGrandGrupo =
            IF(
                _g = "Revenue",
                "",
                IF(
                    _hasRevenue,
                    IF(
                        NOT ISBLANK(_revenueTotalGlobal) && _revenueTotalGlobal <> 0,
                        FORMAT(
                            DIVIDE(
                                _numeradorGrandGrupo,
                                ABS(_revenueTotalGlobal)
                            ),
                            _pctFormat
                        ),
                        ""
                    ),
                    IF(
                        NOT ISBLANK(_totalCostoGlobalGrupo) && _totalCostoGlobalGrupo <> 0,
                        FORMAT(
                            DIVIDE(
                                _numeradorGrandGrupo,
                                _totalCostoGlobalGrupo
                            ),
                            _pctFormat
                        ),
                        ""
                    )
                )
            )

        VAR _filaGrupo =
            "<tr class='gh'
                onclick=""var rows=this.parentNode.querySelectorAll('[data-g=&quot;" & _gid & "&quot;]');
                    var ico=this.querySelector('.ico');
                    var open=ico.textContent==='-';
                    Array.prototype.forEach.call(rows,function(r){ r.style.display=open?'none':''; });
                    ico.textContent=open?'+':'-';
                    this.classList.toggle('active');
                "">
                <td class='sticky-col'>
                    <div class='gl'>
                        <span class='tog'><span class='ico'>-</span></span>" & _g &
                    "</div>
                </td>" &
                _celdasGrupo &
                IF(
                    _Numpozos > 1,
                    "<td class='grandtotal pct-d'>" & _pctGrandGrupo & "</td>" &
                    "<td class='grandtotal" & _grandCls & "'>" & _grandFmt & "</td>",
                    ""
                ) &
            "</tr>"

        -- ==================================================
        -- SUBCLASSES
        -- ==================================================
        VAR _hijos =
            ADDCOLUMNS(
                FILTER(
                    CALCULATETABLE(
                        VALUES( 'origenesdecontabilidad-PL'[SubClassCG] ),
                        'origenesdecontabilidad-PL'[ClassCG] = _g
                    ),
                    NOT ISBLANK( 'origenesdecontabilidad-PL'[SubClassCG] )
                ),
                "ord_h",
                    CALCULATE( MAX( 'origenesdecontabilidad-PL'[SubClassCG_Order] ) )
            )

        VAR _countHijos = COUNTROWS( _hijos )

        VAR _filasHijos =
            CONCATENATEX(
                _hijos,
                VAR _h = 'origenesdecontabilidad-PL'[SubClassCG]
                VAR _indexH = RANKX( _hijos, [ord_h], , ASC, DENSE )

                VAR _providersBase =
                    FILTER(
                        ADDCOLUMNS(
                            SUMMARIZE(
                                FILTER( 'origenesdecontabilidad-PL',
                                    'origenesdecontabilidad-PL'[ClassCG]    = _g &&
                                    'origenesdecontabilidad-PL'[SubClassCG] = _h
                                ),
                                'origenesdecontabilidad-PL'[nombreproveedor]
                            ),
                            "amt",     CALCULATE( SUM( 'origenesdecontabilidad-PL'[amrusd] ) ),
                            "abs_amt", ABS( CALCULATE( SUM( 'origenesdecontabilidad-PL'[amrusd] ) ) )
                        ),
                        [amt] <> 0
                    )

                VAR _providerTooltip =
                    CONCATENATEX(
                        TOPN( 10, _providersBase, [abs_amt], DESC ),
                        'origenesdecontabilidad-PL'[nombreproveedor] & ":::" &
                            FORMAT( ROUND( [amt]/1000, 0 ), "#,##0" ),
                        "|",
                        [abs_amt], DESC
                    )

                -- Valor propio de la subclass (siempre su ClassCG propio, sin acumulados)
                VAR _subclassTotalGlobal =
                    CALCULATE(
                        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                        'origenesdecontabilidad-PL'[ClassCG]    = _g,
                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                    )

                -- Denominador del % según la clase:
                -- Revenue  → sin %
                -- DWP      → total DWP puro
                -- OR       → total OR acumulado (Rev + DWP + OR)
                VAR _orExiste =
                    CALCULATE(
                        COUNTROWS('origenesdecontabilidad-PL'),
                        REMOVEFILTERS('origenesdecontabilidad-PL'[SubClassCG]),
                        'origenesdecontabilidad-PL'[ClassCG] = "Operational Result"
                    ) > 0

                    VAR _totalCostoGlobal =
                        IF(
                            _hasOperationalResult,
                            ABS(
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    REMOVEFILTERS(
                                        'origenesdecontabilidad-PL'[ClassCG],
                                        'origenesdecontabilidad-PL'[SubClassCG]
                                    ),
                                    'origenesdecontabilidad-PL'[ClassCG] IN {
                                        "DWP",
                                        "Operational Result"
                                    }
                                )
                            ),
                            ABS(
                                CALCULATE(
                                    SUM('origenesdecontabilidad-PL'[amrusd]),
                                    REMOVEFILTERS(
                                        'origenesdecontabilidad-PL'[ClassCG],
                                        'origenesdecontabilidad-PL'[SubClassCG]
                                    ),
                                    'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                                )
                            )
                        )

                    VAR _signoPct =
                        IF(
                            _h IN { "Finance Discount", "I/Co Rev" },
                            -1,
                            1
                        )

                    VAR _pctSubclass =
                    IF(
                        _g = "Revenue",
                        "",
                        IF(
                            _hasRevenue,
                            FORMAT(
                                _signoPct *
                                DIVIDE(
                                    ABS(_subclassTotalGlobal),
                                    ABS(_revenueTotalGlobal)
                                ),
                                _pctFormat
                            ),
                            FORMAT(
                                _signoPct *
                                DIVIDE(
                                    ABS(_subclassTotalGlobal),
                                    _totalCostoGlobal
                                ),
                                _pctFormat
                            )
                        )
                    )

                VAR _extraH =
                    IF( [ord_g] = 1 && _indexH = 1, " first-global", "" ) &
                    IF( _indexH = 1, " first", "" ) &
                    IF( _indexH = _countHijos, " last", "" )

                -- Grand sub: valor propio de la subclass (sin acumular otras clases)
                VAR _grandSub =
                    CALCULATE(
                        SUM('origenesdecontabilidad-PL'[amrusd]),
                        'origenesdecontabilidad-PL'[ClassCG]    = _g,
                        'origenesdecontabilidad-PL'[SubClassCG] = _h
                    )

                VAR _grandSubFmt =
                    IF( ISBLANK(_grandSub), "",
                        IF( _grandSub < 0,
                            "-" & FORMAT( ROUND( ABS(_grandSub)/1000, 0 ), "#,##0" ),
                            FORMAT( ROUND( _grandSub/1000, 0 ), "#,##0" )
                        )
                    )
                VAR _grandSubCls = IF( ISBLANK(_grandSub), "", IF( _grandSub < 0, " neg", "" ) )

                VAR _celdasHijo =
                    CONCATENATEX(
                        _pozos,
                        VAR _p = 'origenesdecontabilidad-PL'[pozo]
                        VAR _rankpozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
                        VAR _etapaspozo = FILTER( _pozoEtapa, 'origenesdecontabilidad-PL'[pozo] = _p )

                        -- Valor propio de la subclass por pozo
                        VAR _totalpozo =
                            CALCULATE(
                                SUM('origenesdecontabilidad-PL'[amrusd]),
                                'origenesdecontabilidad-PL'[pozo]       = _p,
                                'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                'origenesdecontabilidad-PL'[ClassCG]    = _g
                            )

                        VAR _fmtTotal =
                            IF( ISBLANK(_totalpozo), "",
                                IF( _totalpozo < 0,
                                    "-" & FORMAT( ROUND( ABS(_totalpozo)/1000, 0 ), "#,##0" ),
                                    FORMAT( ROUND( _totalpozo/1000, 0 ), "#,##0" )
                                )
                            )
                        VAR _clsTotal = IF( ISBLANK(_totalpozo), "", IF( _totalpozo < 0, " neg", "" ) )

                        VAR _tdsEtapas =
                            CONCATENATEX(
                                _etapaspozo,
                                VAR _e = dimensionesfinancieras[etapaestandar]
                                VAR _rankEtapa = RANKX( _etapaspozo, [ord_e], , ASC, DENSE )
                                VAR _v =
                                    CALCULATE(
                                        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                                        'origenesdecontabilidad-PL'[pozo]       = _p,
                                        'origenesdecontabilidad-PL'[ClassCG]    = _g,
                                        'origenesdecontabilidad-PL'[SubClassCG] = _h,
                                        dimensionesfinancieras[etapaestandar]   = _e
                                    )
                                VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                                VAR _fmt =
                                    IF( ISBLANK(_v), "",
                                        IF( _v < 0,
                                            "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                                            FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                                        )
                                    )
                                RETURN
                                    "<td style='display:none;' class='data etapa-total p" & _rankpozo &
                                    " ep" & _rankpozo & "_" & _rankEtapa & _cls & "'>" & _fmt & "</td>",
                                "", [ord_e], ASC
                            )

                        -- Denominador % por pozo según la clase

    VAR _revPozoForPct =
        CALCULATE(
            SUM('origenesdecontabilidad-PL'[amrusd]),
            REMOVEFILTERS('origenesdecontabilidad-PL'[SubClassCG]),
            'origenesdecontabilidad-PL'[ClassCG] = "Revenue",
            'origenesdecontabilidad-PL'[pozo] = _p
        )

    VAR _totalCostoPozo =
        IF(
            _hasOperationalResult,
            ABS(
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    REMOVEFILTERS(
                        'origenesdecontabilidad-PL'[ClassCG],
                        'origenesdecontabilidad-PL'[SubClassCG]
                    ),
                    'origenesdecontabilidad-PL'[ClassCG] IN {
                        "DWP",
                        "Operational Result"
                    },
                    'origenesdecontabilidad-PL'[pozo] = _p
                )
            ),
            ABS(
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    REMOVEFILTERS(
                        'origenesdecontabilidad-PL'[ClassCG],
                        'origenesdecontabilidad-PL'[SubClassCG]
                    ),
                    'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                    'origenesdecontabilidad-PL'[pozo] = _p
                )
            )
        )

        VAR _signoPct =
            IF(
                _h IN { "Finance Discount", "I/Co Rev" },
                -1,
                1
            )

        VAR _pctPozo =
        IF(
            _g = "Revenue",
            "",
            IF(
                _hasRevenue,
                FORMAT(
                    _signoPct *
                    DIVIDE(
                        ABS(_totalpozo),
                        ABS(_revPozoForPct)
                    ),
                    _pctFormat
                ),
                FORMAT(
                    _signoPct *
                    DIVIDE(
                        ABS(_totalpozo),
                        _totalCostoPozo
                    ),
                    _pctFormat
                )
            )
        )

                        RETURN
                            "<td class='pct-d pp" & _rankpozo & "'>" & _pctPozo & "</td>" &
                            _tdsEtapas &
                            "<td class='total pozo-total ptp" & _rankpozo & _clsTotal & "'>" & _fmtTotal & "</td>",
                        "", [ord_p], DESC
                    )

                RETURN
                    "<tr class='sh" & _extraH & "' data-g='" & _gid & "' style='display:table-row'>
                        <td class='sticky-col subclass-cell'
                            data-tip='" & _providerTooltip & "'
                            " & IF( _enableProviderTooltip,
                                "onclick='showProviderTooltip(this,event)'
                                onmouseleave='hideProviderTooltip()'",
                                ""
                            ) & ">
                            <div class='gl'>
                                <span style='width:20px;display:inline-block;'></span>" & _h & "
                            </div>
                        </td>" &
                        _celdasHijo &
                        IF(
                            _Numpozos > 1,
                                "<td class='grandtotal pct-d'>" & _pctSubclass & "</td>" &
                                "<td class='grandtotal " & _grandSubCls & "'>" & _grandSubFmt & "</td>",
                            ""
                        ) &
                    "</tr>",
                "", [ord_h]
            )

        RETURN
            IF(
                _enableRevenueVisible || _g = "DWP" || _g = "Operational Result",
                _filasHijos,
                ""
            ) &
            _filaGrupo,
        "", [ord_g]
    )

-- ============================================================
-- FILA TOTAL DWP (comentada en RETURN pero la dejamos calculada)
-- ============================================================


VAR _dwpTotalGlobal =
    IF(
        _enableRevenueVisible,
        CALCULATE(
            SUM('origenesdecontabilidad-PL'[amrusd]),
            'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP"}
        ),
        CALCULATE(
            SUM('origenesdecontabilidad-PL'[amrusd]),
            'origenesdecontabilidad-PL'[ClassCG] = "DWP"
        )
    )

VAR _dwpTotalFmt =
    IF( ISBLANK(_dwpTotalGlobal), "",
        IF( _dwpTotalGlobal < 0,
            "-" & FORMAT( ROUND( ABS(_dwpTotalGlobal)/1000, 0 ), "#,##0" ),
            FORMAT( ROUND( _dwpTotalGlobal/1000, 0 ), "#,##0" )
        )
    )
VAR _dwpTotalCls = IF( NOT ISBLANK(_dwpTotalGlobal) && _dwpTotalGlobal < 0, " neg", "" )

VAR _celdasTotalDWP =
    CONCATENATEX(
        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[pozo]
        VAR _rankpozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
        VAR _etapaspozo = FILTER( _pozoEtapa, 'origenesdecontabilidad-PL'[pozo] = _p )

        VAR _ptdPozo =
            IF(
                _enableRevenueVisible,
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    'origenesdecontabilidad-PL'[pozo] = _p,
                    'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP"}
                ),
                CALCULATE(
                    SUM('origenesdecontabilidad-PL'[amrusd]),
                    'origenesdecontabilidad-PL'[pozo] = _p,
                    'origenesdecontabilidad-PL'[ClassCG] = "DWP"
                )
            )

        VAR _ptdPozoFmt =
            IF( ISBLANK(_ptdPozo), "",
                IF( _ptdPozo < 0,
                    "-" & FORMAT( ROUND( ABS(_ptdPozo)/1000, 0 ), "#,##0" ),
                    FORMAT( ROUND( _ptdPozo/1000, 0 ), "#,##0" )
                )
            )
        VAR _ptdPozoCls = IF( ISBLANK(_ptdPozo), "", IF( _ptdPozo < 0, " neg", "" ) )

        VAR _tdsEtapas =
            CONCATENATEX(
                _etapaspozo,
                VAR _e = dimensionesfinancieras[etapaestandar]
                VAR _rankEtapa = RANKX( _etapaspozo, [ord_e], , ASC, DENSE )
                VAR _v =
                    CALCULATE(
                        SUM( 'origenesdecontabilidad-PL'[amrusd] ),
                        'origenesdecontabilidad-PL'[pozo]    = _p,
                        'origenesdecontabilidad-PL'[ClassCG] = "DWP",
                        dimensionesfinancieras[etapaestandar] = _e
                    )
                VAR _cls = IF( ISBLANK(_v), "", IF( _v < 0, " neg", "" ) )
                VAR _fmt =
                    IF( ISBLANK(_v), "",
                        IF( _v < 0,
                            "-" & FORMAT( ROUND( ABS(_v)/1000, 0 ), "#,##0" ),
                            FORMAT( ROUND( _v/1000, 0 ), "#,##0" )
                        )
                    )
                RETURN
                    "<td style='display:none;' class='data etapa-total p" & _rankpozo &
                    " ep" & _rankpozo & "_" & _rankEtapa & _cls & "'>" & _fmt & "</td>",
                "", [ord_e], ASC
            )

        RETURN
            "<td class='pct-d pp" & _rankpozo & "'>100%</td>" &
            _tdsEtapas &
            "<td class='total pozo-total ptp" & _rankpozo & _ptdPozoCls & "'>" & _ptdPozoFmt & "</td>",
        "", [ord_p], DESC
    )

VAR _filaTotalDWP =
    "<tr class='total-row'>
        <td class='sticky-col'>
            <div class='gl'>
                <span style='width:20px;display:inline-block;'></span>Total
            </div>
        </td>" &
        _celdasTotalDWP &
        IF(
            _Numpozos > 1,
                "<td class='grandtotal pct-d'>100%</td>" &
                "<td class='grandtotal" & _dwpTotalCls & "'>" & _dwpTotalFmt & "</td>",
            ""
        ) &
    "</tr>"

-- ============================================================
-- FILA % DE INGRESO
-- Ahora basado en Operational Result (Rev + DWP + OR) / Revenue
-- ============================================================

-- % de Ingreso = OR acumulado / Revenue
VAR _pctResumenPTD =
    IF(
        _hasRevenue,
        FORMAT( DIVIDE( _orTotalGlobal, _revenueTotalGlobal ), _pctFormat ),
        "100%"
    )

VAR _celdasIngresoPozo =
    CONCATENATEX(
        _pozos,
        VAR _p = 'origenesdecontabilidad-PL'[pozo]
        VAR _rankpozo = RANKX( _pozos, [ord_p], , DESC, DENSE )
        VAR _etapaspozo = FILTER( _pozoEtapa, 'origenesdecontabilidad-PL'[pozo] = _p )

        VAR _revPozo =
            CALCULATE(
                SUM('origenesdecontabilidad-PL'[amrusd]),
                REMOVEFILTERS('origenesdecontabilidad-PL'[SubClassCG]),
                KEEPFILTERS( 'origenesdecontabilidad-PL'[ClassCG] = "Revenue" ),
                'origenesdecontabilidad-PL'[pozo] = _p
            )

        -- OR acumulado por pozo (Rev + DWP + OR)
        VAR _orPozo =
            CALCULATE(
                SUM('origenesdecontabilidad-PL'[amrusd]),
                'origenesdecontabilidad-PL'[ClassCG] IN {"Revenue","DWP","Operational Result"},
                'origenesdecontabilidad-PL'[pozo] = _p
            )

        -- OR acumulado / Revenue por pozo
        VAR _pctPTDPozo =
            IF(
                _hasRevenue,
                FORMAT( DIVIDE( _orPozo, _revPozo ), _pctFormat ),
                "100%"
            )

        VAR _tdsEtapas =
        CONCATENATEX(
        _etapaspozo,
        VAR _e = dimensionesfinancieras[etapaestandar]
        VAR _rankEtapa = RANKX( _etapaspozo, [ord_e], , ASC, DENSE )

        VAR _revEtapaPozo =
            CALCULATE(
                SUM('origenesdecontabilidad-PL'[amrusd]),
                REMOVEFILTERS('origenesdecontabilidad-PL'[SubClassCG]),
                KEEPFILTERS( 'origenesdecontabilidad-PL'[ClassCG] = "Revenue" ),
                'origenesdecontabilidad-PL'[pozo] = _p,
                dimensionesfinancieras[etapaestandar] = _e
            )

        -- Suma con signo de hijos DWP + OR de esa etapa y pozo
        VAR _hijosDWPEtapa =
            CALCULATE(
                SUM('origenesdecontabilidad-PL'[amrusd]),
                'origenesdecontabilidad-PL'[ClassCG] IN {"DWP","Operational Result"},
                'origenesdecontabilidad-PL'[pozo]    = _p,
                dimensionesfinancieras[etapaestandar] = _e
            )

        -- Acumulado = Rev + hijos DWP + hijos OR (con signo)
        VAR _acumEtapa = _revEtapaPozo + _hijosDWPEtapa

        VAR _pctEtapa =
            IF(
                _hasRevenue,
                IF(
                    NOT ISBLANK(_revEtapaPozo) && _revEtapaPozo <> 0,
                    FORMAT( DIVIDE( _acumEtapa, _revEtapaPozo ), "0%" ),
                    ""
                ),
                IF(
                    NOT ISBLANK(_orPozo) && _orPozo <> 0,
                    FORMAT( DIVIDE( ABS(_acumEtapa), ABS(_orPozo) ), "0%" ),
                    ""
                )
            )

        RETURN
            "<td style='display:none;'
                class='data etapa-total p" & _rankpozo &
                " ep" & _rankpozo & "_" & _rankEtapa & "'>" &
                _pctEtapa &
            "</td>",
        "", [ord_e], ASC
    )

        RETURN
            "<td class='pct-d pp" & _rankpozo & "'></td>" &
            _tdsEtapas &
            "<td class='total pozo-total ptp" & _rankpozo & "'>" & _pctPTDPozo & "</td>",
        "", [ord_p], DESC
    )

VAR _filaIngreso =
    "<tr class='income-row'>
        <td class='sticky-col'>
            <div class='gl'>
                <span style='width:20px;display:inline-block;'></span>"
                & IF( _hasRevenue, "% de Ingreso", "% de Costo" ) &"
            </div>
        </td>" &
        _celdasIngresoPozo &
        IF(
            _Numpozos > 1,
                "<td class='grandtotal pct-d'></td>" &
                "<td class='grandtotal'>" & _pctResumenPTD & "</td>",
            ""
        ) &
    "</tr>"

-- ============================================================
-- SCRIPT JS
-- ============================================================
VAR _script = "
<script>

function setpozoState(rank, level) {
    var hp = document.getElementById('hp' + rank);
    if (!hp) return;

    level = parseInt(level, 10);
    if (isNaN(level) || level < 0) level = 0;
    if (level > 1) level = 1;

    var numEtapas = parseInt(hp.getAttribute('data-etapas'), 10);
    if (isNaN(numEtapas) || numEtapas < 1) numEtapas = 0;

    var etapaCols = document.querySelectorAll('td.p' + rank + '.etapa-total, th.p' + rank + '.etapa-total, .ep' + rank);
    etapaCols.forEach(function(c) { c.style.display = 'none'; });

    var epCols = document.querySelectorAll('[class*=""ep' + rank + '_""]');
    epCols.forEach(function(c) { c.style.display = 'none'; });

    if (level === 0) {
        hp.setAttribute('colspan', 2);
    }

    if (level === 1) {
        epCols.forEach(function(c) { c.style.display = ''; });
        hp.setAttribute('colspan', numEtapas + 2);
    }

    hp.setAttribute('data-level', level);

    var BG_TOTAL = '#f4f6fb';
    var totalCells = document.querySelectorAll('tr.sh td.ptp' + rank);
    totalCells.forEach(function(c) {
        c.style.background = level === 1 ? BG_TOTAL : '';
    });

    var firstTotalCells = document.querySelectorAll('tr.sh.first td.ptp' + rank);
    firstTotalCells.forEach(function(c) {
        if (level === 1) {
            c.style.setProperty('border-top', '15px solid ' + BG_TOTAL, 'important');
        } else {
            c.style.removeProperty('border-top');
        }
    });
}

function getpozoRanks() {
    return Array.prototype.slice.call(
        document.querySelectorAll('th.ph')
    ).map(function(h) {
        return h.id.replace('hp', '').trim();
    });
}

function getpozoGlobalLevel(ranks) {
    var maxLevel = 0;
    ranks.forEach(function(rank) {
        var hp = document.getElementById('hp' + rank);
        var level = hp ? parseInt(hp.getAttribute('data-level'), 10) : 0;
        if (isNaN(level)) level = 0;
        if (level > maxLevel) maxLevel = level;
    });
    return maxLevel;
}

function expandAllpozos() {
    var ranks = getpozoRanks();
    var targetLevel = Math.min(getpozoGlobalLevel(ranks) + 1, 1);
    ranks.forEach(function(rank) { setpozoState(rank, targetLevel); });
}

function collapseAllpozos() {
    var ranks = getpozoRanks();
    var targetLevel = Math.max(getpozoGlobalLevel(ranks) - 1, 0);
    ranks.forEach(function(rank) { setpozoState(rank, targetLevel); });
}

function showProviderTooltip(el, evt) {
    var tooltip = document.getElementById('providerTooltip');
    if (!tooltip) return;
    var raw = el.getAttribute('data-tip');
    if (!raw || raw.trim() === '') return;
    var rows = raw.split('|');
    var html = '<div class=""tt-title"">Top 10 Proveedores / Clientes</div>';
    rows.forEach(function(r) {
        var p = r.split(':::');
        var name = p[0] || '';
        var val  = p[1] || '';
        var cls  = val.indexOf('-') >= 0 ? 'tt-val neg' : 'tt-val';
        html += '<div class=""tt-row""><span class=""tt-name"">' + name + '</span><span class=""' + cls + '"">' + val + '</span></div>';
    });
    tooltip.innerHTML = html;
    tooltip.style.display = 'block';
    var left = evt.pageX + 15;
    var top  = evt.pageY + 15;
    if (top  + tooltip.offsetHeight > window.innerHeight) top  = evt.pageY - tooltip.offsetHeight - 25;
    if (left + tooltip.offsetWidth  > window.innerWidth)  left = evt.pageX - tooltip.offsetWidth  - 25;
    tooltip.style.left = left + 'px';
    tooltip.style.top  = top  + 'px';
}

function hideProviderTooltip() {
    var t = document.getElementById('providerTooltip');
    if (t) t.style.display = 'none';
}

</script>
